import { Order, Subscription, SiteContent, Meal, SubscriptionPlan, PromoCode } from '../types';
import { MEALS } from '../constants';
import { db } from './firebase';
import { collection, getDocs, doc, setDoc, updateDoc, deleteDoc, getDoc } from 'firebase/firestore';

// In-memory cache for persistence within session if DB writes fail (e.g. permission issues)
let localPlans: SubscriptionPlan[] = [];
let localPromos: PromoCode[] = [];
let localOrders: Order[] = [];
let localSubscriptions: Subscription[] = [];

export const dataService = {
  // Orders
  getOrders: async (): Promise<Order[]> => {
    let orders: Order[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "orders"));
      querySnapshot.forEach((doc) => {
        orders.push(doc.data() as Order);
      });
    } catch (e) {
      console.warn("Using local/empty orders due to DB error");
    }

    // Merge with localOrders
    localOrders.forEach(localOrder => {
        const index = orders.findIndex(o => o.id === localOrder.id);
        if (index !== -1) {
            orders[index] = localOrder;
        } else {
            orders.push(localOrder);
        }
    });

    return orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  },

  saveOrder: async (order: Order) => {
    // Save locally first
    const existingIndex = localOrders.findIndex(o => o.id === order.id);
    if (existingIndex >= 0) {
        localOrders[existingIndex] = order;
    } else {
        localOrders.push(order);
    }

    try {
      await setDoc(doc(db, "orders", order.id), order);
    } catch (e) {
      console.warn("Failed to save order to DB", e);
    }
  },

  updateOrderStatus: async (id: string, status: 'pending' | 'completed' | 'cancelled') => {
    // Update local
    const localOrder = localOrders.find(o => o.id === id);
    if (localOrder) {
        localOrder.status = status;
    }

    try {
      const orderRef = doc(db, "orders", id);
      await updateDoc(orderRef, { status: status });
    } catch (e) {
      console.warn("Failed to update order status", e);
    }
  },

  // Subscriptions
  getSubscriptions: async (): Promise<Subscription[]> => {
    let subs: Subscription[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "subscriptions"));
      querySnapshot.forEach((doc) => {
        subs.push(doc.data() as Subscription);
      });
    } catch (e) {
      console.warn("Using local/empty subscriptions due to DB error");
    }

    // Merge with localSubscriptions
    localSubscriptions.forEach(localSub => {
         const index = subs.findIndex(s => s.id === localSub.id);
         if (index !== -1) {
             subs[index] = localSub;
         } else {
             subs.push(localSub);
         }
    });

    return subs.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  },

  saveSubscription: async (sub: Subscription) => {
    const id = sub.id || `sub_${Date.now()}`;
    const subWithId = { ...sub, id };

    // Save locally
    const existingIndex = localSubscriptions.findIndex(s => s.id === id);
    if (existingIndex >= 0) {
        localSubscriptions[existingIndex] = subWithId;
    } else {
        localSubscriptions.push(subWithId);
    }

    try {
      await setDoc(doc(db, "subscriptions", id), subWithId);
    } catch (e) {
      console.warn("Failed to save subscription", e);
    }
  },

  // Content
  getContent: async (): Promise<SiteContent> => {
    const defaults: SiteContent = {
        heroTitle: 'نمط حياة خفيف وصحي للجميع',
        heroSubtitle: 'انكل هيلثي هو وجهتك الأولى للوجبات الصحية الفاخرة. نجمع بين الذكاء الاصطناعي والمكونات الطبيعية 100% لنقدم لك تجربة غذائية لا تُنسى.',
        heroImage: 'https://i.ibb.co/6J8BHK9s/28.jpg',
        missionTitle: 'مهمتنا',
        missionText: 'توفير وجبات صحية فاخرة مصنوعة من مكونات طبيعية 100%. نحن نجعل الحياة الصحية بسيطة، لذيذة، ومتاحة للجميع.',
        featuresList: [
            'مكونات طبيعية 100%',
            'استشارات مدعومة بالذكاء الاصطناعي',
            'نظام اشتراك مرن',
            'توصيل دقيق في الموعد'
        ],
        geminiApiKey: '',
        appBannerTitle1: 'صحتك صارت',
        appBannerHighlight: 'أسهل وأقرب',
        appBannerText: 'حمل التطبيق الآن واستمتع بتجربة طلب أسرع، تتبع لخطتك الغذائية، وعروض حصرية. وجباتك الصحية بلمسة زر.',
        appBannerImage: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
        privacyPolicy: 'نحن نلتزم بحماية خصوصيتك. يتم استخدام بياناتك فقط لتحسين تجربتك وتوصيل طلباتك.',
        returnPolicy: 'نظراً لطبيعة المنتجات الغذائية، لا يمكن إرجاع الطلبات بعد استلامها إلا في حال وجود عيب مصنعي أو خطأ في الطلب.',
        paymentPolicy: 'نقبل الدفع نقداً عند الاستلام، أو عبر المحافظ الإلكترونية والبطاقات الائتمانية.',
        socialFacebook: 'https://facebook.com',
        socialInstagram: 'https://instagram.com',
        socialTwitter: 'https://twitter.com',
        linkAndroid: '',
        linkIOS: ''
    };

    try {
      const docRef = doc(db, "content", "main_content");
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data() as SiteContent;
        return { 
            ...defaults, 
            ...data, 
            featuresList: data.featuresList || defaults.featuresList,
            geminiApiKey: data.geminiApiKey || defaults.geminiApiKey
        };
      } else {
        try { await setDoc(docRef, defaults); } catch(err) {}
        return defaults;
      }
    } catch (e) {
      console.warn("Firebase content unavailable, using defaults.");
      return defaults;
    }
  },

  saveContent: async (content: SiteContent): Promise<boolean> => {
    try {
      await setDoc(doc(db, "content", "main_content"), content);
      return true;
    } catch (e) {
      console.warn("Failed to save content", e);
      return false;
    }
  },

  // Meals
  getMeals: async (): Promise<Meal[]> => {
    try {
      const querySnapshot = await getDocs(collection(db, "meals"));
      const meals: Meal[] = [];
      querySnapshot.forEach((doc) => {
        meals.push(doc.data() as Meal);
      });

      if (meals.length === 0) {
        // Seed Defaults
        try {
            for (const m of MEALS) {
                await setDoc(doc(db, "meals", m.id), m);
            }
        } catch(err) {}
        return MEALS;
      }
      return meals;
    } catch (e) {
      return MEALS;
    }
  },
  addMeal: async (meal: Meal) => {
    try {
        await setDoc(doc(db, "meals", meal.id), meal);
    } catch (e) {
        console.warn("Failed to add meal");
    }
  },
  deleteMeal: async (id: string) => {
    try {
        await deleteDoc(doc(db, "meals", id));
    } catch (e) {
        console.warn("Failed to delete meal");
    }
  },

  // Subscription Plans Management
  getSubscriptionPlans: async (): Promise<SubscriptionPlan[]> => {
    let plans: SubscriptionPlan[] = [];

    // 1. Try Fetch from DB
    try {
      const querySnapshot = await getDocs(collection(db, "plans"));
      querySnapshot.forEach((doc) => {
        plans.push(doc.data() as SubscriptionPlan);
      });
    } catch (e) {
      // Ignore DB error, proceed to use local/defaults
    }

    // 2. Merge with Local Plans (Added in this session but failed to save to DB)
    localPlans.forEach(lp => {
        // Update if exists, else add
        const idx = plans.findIndex(p => p.id === lp.id);
        if (idx >= 0) {
            plans[idx] = lp;
        } else {
            plans.push(lp);
        }
    });

    // 3. If still empty, use Defaults
    if (plans.length === 0) {
         const defaults: SubscriptionPlan[] = [
            { 
              id: 'plan_slimming', 
              title: 'باقة الرشاقة (تخفيف)', 
              price: 130, 
              image: 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
              features: ['وجبتين يومياً (غداء + عشاء)', 'اشتراك لمدة 24 يوم', 'سناك صحي يومي', 'توصيل مجاني'], 
              durationLabel: 'شهر', 
              isPopular: false 
            },
            { 
              id: 'plan_muscle', 
              title: 'باقة العضلات (تضخيم)', 
              price: 175, 
              image: 'https://images.unsplash.com/photo-1543362906-ac1b48263852?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
              features: ['3 وجبات بروتين عالي', 'اشتراك لمدة 26 يوم', '2 سناك بروتين', 'استشارة كابتن مجانية'], 
              durationLabel: 'شهر', 
              isPopular: true 
            },
            { 
              id: 'plan_lifestyle', 
              title: 'باقة لايف ستايل', 
              price: 90, 
              image: 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
              features: ['وجبة غداء يومية للعمل', 'اشتراك لمدة 20 يوم', 'توصيل مكتبي', 'مرونة في التوقيت'], 
              durationLabel: 'شهر', 
              isPopular: false 
            },
            { 
              id: 'plan_vip', 
              title: 'باقة VIP الملكية', 
              price: 260, 
              image: 'https://images.unsplash.com/photo-1547592180-85f173990554?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
              features: ['4 وجبات كاملة يومياً', 'مشروبات ديتوكس', 'متابعة أسبوعية خاصة', 'أولوية قصوى في التوصيل'], 
              durationLabel: 'شهر', 
              isPopular: false 
            },
         ];
         return defaults;
    }
    return plans;
  },

  saveSubscriptionPlan: async (plan: SubscriptionPlan) => {
    // Optimistic: Always save locally first
    const existingIndex = localPlans.findIndex(p => p.id === plan.id);
    if (existingIndex >= 0) {
        localPlans[existingIndex] = plan;
    } else {
        localPlans.push(plan);
    }

    try {
        await setDoc(doc(db, "plans", plan.id), plan);
    } catch (e) {
        console.warn("Failed to save plan to DB (likely permission issue). Saved locally.");
    }
  },

  deleteSubscriptionPlan: async (id: string) => {
    localPlans = localPlans.filter(p => p.id !== id);
    try {
        await deleteDoc(doc(db, "plans", id));
    } catch (e) {
        console.warn("Failed to delete plan from DB");
    }
  },

  // Promo Codes Management
  getPromoCodes: async (): Promise<PromoCode[]> => {
    let promos: PromoCode[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "promos"));
      querySnapshot.forEach((doc) => {
        promos.push(doc.data() as PromoCode);
      });
    } catch (e) {}

    // Merge Local
    localPromos.forEach(lp => {
         const idx = promos.findIndex(p => p.id === lp.id);
         if (idx >= 0) promos[idx] = lp;
         else promos.push(lp);
    });

    return promos;
  },

  savePromoCode: async (promo: PromoCode) => {
    // Optimistic Save
    const idx = localPromos.findIndex(p => p.id === promo.id);
    if (idx >= 0) localPromos[idx] = promo;
    else localPromos.push(promo);

    try {
        await setDoc(doc(db, "promos", promo.id), promo);
    } catch (e) {
        console.warn("Failed to save promo to DB. Saved locally.");
    }
  },

  deletePromoCode: async (id: string) => {
    localPromos = localPromos.filter(p => p.id !== id);
    try {
        await deleteDoc(doc(db, "promos", id));
    } catch (e) {}
  },

  verifyPromoCode: async (code: string, type: 'MEALS' | 'SUBSCRIPTION'): Promise<PromoCode | null> => {
     // Fetch using the main getter which combines DB and Local
     const allPromos = await dataService.getPromoCodes();
     return allPromos.find(p => p.code === code && p.isActive && p.type === type) || null;
  }
};

import React, { useState, useEffect } from 'react';
import { UserProfile, Order, Subscription, SiteContent, Meal, SubscriptionPlan, PromoCode } from '../types';
import { authService } from '../services/authService';
import { dataService } from '../services/dataService';
import { ShoppingBag, Users, FileText, Calendar, Package, LogOut, Check, X, Trash2, Plus, Settings, Key, Shield, Smartphone, Tag, LayoutList, Menu, Edit, Zap, MessageCircle, Phone, MapPin, Clock } from 'lucide-react';
import { INITIAL_USER_PROFILE, MEALS } from '../constants';
import { ImageUploader } from './ImageUploader';

interface AdminDashboardProps {
  onLogout: () => void;
}

type Tab = 'ORDERS' | 'STORE' | 'USERS' | 'CONTENT' | 'SUBSCRIPTIONS' | 'PLANS' | 'PROMO';

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>('ORDERS');
  const [isSidebarOpen, setSidebarOpen] = useState(false);

  // Data State
  const [orders, setOrders] = useState<Order[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [meals, setMeals] = useState<Meal[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [promos, setPromos] = useState<PromoCode[]>([]);

  const [content, setContent] = useState<SiteContent>({
      heroTitle: '', heroSubtitle: '', heroImage: '', missionTitle: '', missionText: '', featuresList: [],
      geminiApiKey: '',
      appBannerTitle1: '', appBannerHighlight: '', appBannerText: '', appBannerImage: '',
      privacyPolicy: '', returnPolicy: '', paymentPolicy: '', socialFacebook: '', socialInstagram: '', socialTwitter: '',
      linkAndroid: '', linkIOS: ''
  });

  // Modal State
  const [showPlanModal, setShowPlanModal] = useState(false);
  const [newPlan, setNewPlan] = useState<Partial<SubscriptionPlan>>({
      title: '', price: 0, features: [], durationLabel: 'شهر', image: ''
  });
  const [planFeaturesText, setPlanFeaturesText] = useState('');

  const [showPromoModal, setShowPromoModal] = useState(false);
  const [newPromo, setNewPromo] = useState<Partial<PromoCode>>({
      code: '', discountAmount: 0, isPercentage: false, type: 'SUBSCRIPTION', isActive: true
  });

  // Meal Modal State
  const [showMealModal, setShowMealModal] = useState(false);
  const [newMeal, setNewMeal] = useState<Partial<Meal>>({
      name: '', description: '', image: '', price: 0, 
      macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
      ingredients: [], instructions: []
  });
  const [mealIngredientsText, setMealIngredientsText] = useState('');
  const [mealInstructionsText, setMealInstructionsText] = useState('');

  // Load Data
  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setOrders(await dataService.getOrders());
    setUsers(await authService.getAllUsers());
    setSubscriptions(await dataService.getSubscriptions());
    setMeals(await dataService.getMeals());
    setContent(await dataService.getContent());
    setPlans(await dataService.getSubscriptionPlans());
    setPromos(await dataService.getPromoCodes());
  };

  // Actions
  const handleUpdateOrderStatus = async (id: string, status: 'pending' | 'completed' | 'cancelled') => {
      await dataService.updateOrderStatus(id, status);
      setOrders(await dataService.getOrders());
  };

  const handleSaveContent = async (e: React.FormEvent) => {
      e.preventDefault();
      await dataService.saveContent(content);
      alert('تم حفظ المحتوى والإعدادات بنجاح');
  };

  const handleDeleteMeal = async (id: string) => {
      if(confirm('هل أنت متأكد من حذف هذه الوجبة؟')) {
          await dataService.deleteMeal(id);
          setMeals(await dataService.getMeals());
      }
  };

  const handleEditMeal = (meal: Meal) => {
      setNewMeal({...meal});
      setMealIngredientsText(meal.ingredients.join('\n'));
      setMealInstructionsText(meal.instructions.join('\n'));
      setShowMealModal(true);
  };

  const handleOpenAddMeal = () => {
      setNewMeal({
         name: '', description: '', image: '', price: 0, 
         macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
         ingredients: [], instructions: []
      });
      setMealIngredientsText('');
      setMealInstructionsText('');
      setShowMealModal(true);
  };

  const handleSaveMeal = async () => {
      if (!newMeal.name || !newMeal.price) {
          alert('الرجاء إدخال اسم الوجبة والسعر');
          return;
      }

      // Check if updating existing or creating new
      const idToUse = newMeal.id || `m_${Date.now()}`;

      const mealToSave: Meal = {
          id: idToUse,
          name: newMeal.name,
          description: newMeal.description || '',
          image: newMeal.image || 'https://picsum.photos/400/300',
          price: Number(newMeal.price),
          macros: newMeal.macros || { protein: 0, carbs: 0, fats: 0, calories: 0 },
          ingredients: mealIngredientsText.split('\n').filter(i => i.trim()),
          instructions: mealInstructionsText.split('\n').filter(i => i.trim())
      };

      try {
          await dataService.addMeal(mealToSave);
          alert(newMeal.id ? 'تم تحديث الوجبة بنجاح!' : 'تم إضافة الوجبة بنجاح!');
          setMeals(await dataService.getMeals());
          setShowMealModal(false);
          setNewMeal({
             name: '', description: '', image: '', price: 0, 
             macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
             ingredients: [], instructions: []
          });
          setMealIngredientsText('');
          setMealInstructionsText('');
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الوجبة');
      }
  };

  const handleSavePlan = async () => {
      if (!newPlan.title) {
          alert('الرجاء إدخال اسم الباقة');
          return;
      }
      if (!newPlan.price || Number(newPlan.price) <= 0) {
          alert('الرجاء إدخال سعر صحيح للباقة');
          return;
      }

      const planToSave: SubscriptionPlan = {
          id: `plan_${Date.now()}`,
          title: newPlan.title,
          price: Number(newPlan.price),
          durationLabel: newPlan.durationLabel || 'شهر',
          image: newPlan.image || 'https://images.unsplash.com/photo-1543362906-ac1b48263852?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
          features: planFeaturesText.split('\n').filter(f => f.trim() !== ''),
          isPopular: false
      };

      try {
          await dataService.saveSubscriptionPlan(planToSave);
          alert('تم إضافة الباقة بنجاح!');
          setPlans(await dataService.getSubscriptionPlans());
          setShowPlanModal(false);
          setNewPlan({ title: '', price: 0, features: [], durationLabel: 'شهر', image: '' });
          setPlanFeaturesText('');
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الباقة، يرجى المحاولة مرة أخرى.');
      }
  };

  const handleDeletePlan = async (id: string) => {
      if(confirm('حذف هذه الباقة؟')) {
          await dataService.deleteSubscriptionPlan(id);
          setPlans(await dataService.getSubscriptionPlans());
      }
  };

  const handleSavePromo = async () => {
      if (!newPromo.code) {
          alert('الرجاء إدخال كود الخصم');
          return;
      }
      if (!newPromo.discountAmount || Number(newPromo.discountAmount) <= 0) {
          alert('الرجاء إدخال قيمة الخصم');
          return;
      }

      const promoToSave: PromoCode = {
          id: `promo_${Date.now()}`,
          code: newPromo.code.toUpperCase(),
          discountAmount: Number(newPromo.discountAmount),
          type: newPromo.type as 'MEALS' | 'SUBSCRIPTION',
          isPercentage: newPromo.isPercentage || false,
          isActive: true
      };

      try {
          await dataService.savePromoCode(promoToSave);
          alert('تم إضافة كود الخصم بنجاح!');
          setPromos(await dataService.getPromoCodes());
          setShowPromoModal(false);
          setNewPromo({ code: '', discountAmount: 0, isPercentage: false, type: 'SUBSCRIPTION', isActive: true });
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الكود.');
      }
  };

  const handleDeletePromo = async (id: string) => {
      if(confirm('حذف هذا الكود؟')) {
          await dataService.deletePromoCode(id);
          setPromos(await dataService.getPromoCodes());
      }
  };

  // Render Helpers
  const renderSidebarItem = (tab: Tab, label: string, Icon: any) => (
      <button 
        onClick={() => { setActiveTab(tab); setSidebarOpen(false); }}
        className={`flex items-center gap-3 w-full p-3 rounded-lg transition ${activeTab === tab ? 'bg-uh-gold text-uh-dark font-bold' : 'text-gray-400 hover:bg-white/10 hover:text-white'}`}
      >
          <Icon size={20} />
          <span>{label}</span>
      </button>
  );

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden font-arabic" dir="rtl">
      {/* Sidebar (Desktop) */}
      <aside className={`fixed inset-y-0 right-0 z-50 w-64 bg-uh-dark text-white transform transition-transform duration-300 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
         <div className="p-6 border-b border-white/10 flex justify-between items-center">
             <h2 className="text-xl font-brand font-bold text-white">لوحة التحكم</h2>
             <button onClick={() => setSidebarOpen(false)} className="md:hidden text-gray-400"><X /></button>
         </div>
         <nav className="p-4 space-y-2 overflow-y-auto h-[calc(100vh-80px)]">
             {renderSidebarItem('ORDERS', 'الطلبات', ShoppingBag)}
             {renderSidebarItem('SUBSCRIPTIONS', 'الاشتراكات', Calendar)}
             {renderSidebarItem('STORE', 'إدارة الوجبات', Package)}
             {renderSidebarItem('USERS', 'المستخدمين', Users)}
             {renderSidebarItem('PLANS', 'خطط الاشتراك', LayoutList)}
             {renderSidebarItem('PROMO', 'كوبونات الخصم', Tag)}
             {renderSidebarItem('CONTENT', 'محتوى الموقع', FileText)}

             <div className="pt-8 mt-8 border-t border-white/10">
                 <button onClick={onLogout} className="flex items-center gap-3 w-full p-3 text-red-400 hover:bg-red-500/10 hover:text-red-500 rounded-lg transition">
                     <LogOut size={20} />
                     <span>تسجيل خروج</span>
                 </button>
             </div>
         </nav>
