                          />
                          <div className="flex gap-2">
                             <input 
                                type="number"
                                placeholder="القيمة" 
                                className="w-1/2 border p-3 rounded-lg"
                                value={newPromo.discountAmount || ''}
                                onChange={e => setNewPromo({...newPromo, discountAmount: Number(e.target.value)})}
