                            { label: 'عشاء', meal: day.dinner }
                        ].map((item, i) => (
                            <div key={i} className="flex gap-3 items-start bg-uh-cream/30 p-3 rounded-lg hover:bg-uh-cream transition">
                                <div className="w-16 h-16 flex-shrink-0 cursor-pointer" onClick={() => onMealClick(item.meal.id)}>
                                    <OptimizedImage src={item.meal.image} alt="" width={150} className="rounded-md w-full h-full" />
                                </div>
                                <div className="flex-1">
                                    <span className="text-xs font-bold text-uh-gold uppercase block">{item.label}</span>
                                    <h5 className="font-bold text-sm text-uh-dark mb-1 cursor-pointer hover:text-uh-green" onClick={() => onMealClick(item.meal.id)}>{item.meal.name}</h5>
                                    <div className="flex gap-2">
                                        <button onClick={() => onMealClick(item.meal.id)} className="text-xs flex items-center gap-1 text-gray-500 hover:text-uh-green">
                                            <ChefHat size={12} /> الوصفة
                                        </button>
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onAddToCart(item.meal); }}
                                            className="text-xs flex items-center gap-1 text-uh-dark hover:text-uh-gold"
                                        >
                                            <ShoppingCart size={12} /> طلب
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Subscription as SubscriptionModel, DeliverySlot, SubscriptionPlan } from '../types';
import { dataService } from '../services/dataService';
import { Check, Clock, MapPin, Truck, Tag, Edit3, Phone } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

export const Subscription: React.FC = () => {
  const [step, setStep] = useState(1);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [selectedPlanId, setSelectedPlanId] = useState<string | null>(null);

  const [subData, setSubData] = useState<Partial<SubscriptionModel>>({
    deliverySlot: DeliverySlot.MORNING,
    address: '',
    phone: '',
    notes: ''
  });

  // Promo Logic
  const [promoCode, setPromoCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [appliedPromo, setAppliedPromo] = useState<string | null>(null);
  const [promoMessage, setPromoMessage] = useState('');

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchPlans = async () => {
        setPlans(await dataService.getSubscriptionPlans());
    };
    fetchPlans();
  }, []);

  const handleSelectPlan = (id: string) => {
    setSelectedPlanId(id);
    setSubData(prev => ({ ...prev, duration: id }));
    setStep(2);
    // Reset Promo when changing plans
    setDiscount(0);
    setAppliedPromo(null);
    setPromoCode('');
    setPromoMessage('');
  };

  const handleApplyPromo = async () => {
      if (!promoCode) return;

      const promo = await dataService.verifyPromoCode(promoCode.toUpperCase(), 'SUBSCRIPTION');
      if (promo) {
          const selectedPlan = plans.find(p => p.id === selectedPlanId);
          if (selectedPlan) {
             let discVal = 0;
             if (promo.isPercentage) {
                 discVal = selectedPlan.price * (promo.discountAmount / 100);
             } else {
                 discVal = promo.discountAmount;
             }
             setDiscount(discVal);
             setAppliedPromo(promo.code);
             setPromoMessage('تم تفعيل الخصم بنجاح! 🎉');
          }
      } else {
          setPromoMessage('كود الخصم غير صالح أو غير مخصص للاشتراكات ❌');
          setDiscount(0);
          setAppliedPromo(null);
      }
  };

  const handleDetailsSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const selectedPlan = plans.find(p => p.id === selectedPlanId);

    if(subData.address && subData.phone && selectedPlanId && subData.deliverySlot && selectedPlan) {
        const finalPrice = Math.max(0, selectedPlan.price - discount);

        try {
            await dataService.saveSubscription({
                duration: selectedPlan.durationLabel, // Store label for readability
                deliverySlot: subData.deliverySlot,
                address: subData.address,
                phone: subData.phone,
                notes: subData.notes, // Save notes
                date: new Date().toISOString(),
                planTitle: selectedPlan.title,
                pricePaid: finalPrice
            });
            alert('تم استلام طلب الاشتراك بنجاح! سيتواصل معك فريقنا قريباً.');
            setStep(1);
            setSelectedPlanId(null);
            setSubData({ deliverySlot: DeliverySlot.MORNING, address: '', phone: '', notes: '' });
        } catch (error) {
            console.error(error);
            alert("عذراً، حدث خطأ أثناء حفظ الاشتراك في قاعدة البيانات. يرجى المحاولة مرة أخرى.");
        }
    }

    setLoading(false);
  };

  const selectedPlan = plans.find(p => p.id === selectedPlanId);

  return (
    <div className="max-w-4xl mx-auto py-8 mb-20 md:mb-0">
      <div className="text-center mb-12">
        <h2 className="text-3xl font-brand text-uh-dark">اختر باقتك</h2>
        <p className="text-gray-500">وجبات صحية تصلك إلى باب بيتك</p>
      </div>

      {step === 1 && (
        <div className="grid md:grid-cols-2 gap-8 animate-fade-in">
          {plans.map(plan => (
            <div key={plan.id} className="bg-white rounded-3xl shadow-lg border-2 border-transparent hover:border-uh-green transition relative overflow-hidden group flex flex-col">
              {plan.image && (
                <div className="h-48 overflow-hidden">
                    <OptimizedImage src={plan.image} alt={plan.title} width={600} className="w-full h-full group-hover:scale-105 transition" />
                </div>
              )}

              {plan.isPopular && (
                  <div className="absolute top-0 right-0 bg-uh-gold text-uh-dark px-4 py-1 rounded-bl-xl text-sm font-bold shadow-sm z-10">الأكثر طلباً</div>
              )}

              <div className="p-8 flex flex-col flex-1">
                <h3 className="text-2xl font-bold mb-2 text-uh-dark">{plan.title}</h3>
                <div className="text-4xl font-brand text-uh-greenDark mb-6">{plan.price} <span className="text-lg text-gray-400">د.أ</span> <span className="text-sm text-gray-400 font-sans">/ {plan.durationLabel}</span></div>

                <ul className="space-y-4 mb-8 flex-1">
                    {plan.features.map((f, i) => (
                        <li key={i} className="flex items-center gap-3 text-gray-600">
                            <Check className="text-uh-green" size={18} />
                            {f}
                        </li>
                    ))}
                </ul>
                <button 
                    onClick={() => handleSelectPlan(plan.id)}
                    className="w-full bg-uh-dark text-white py-3 rounded-xl font-bold hover:bg-black transition"
                >
                    اختيار الباقة
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {step === 2 && selectedPlan && (
        <div className="bg-white rounded-3xl shadow-xl p-8 max-w-2xl mx-auto animate-fade-in">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                <Truck className="text-uh-gold" />
                تفاصيل الاشتراك: <span className="text-uh-green">{selectedPlan.title}</span>
            </h3>

            <form onSubmit={handleDetailsSubmit} className="space-y-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <MapPin size={16}/> عنوان التوصيل بالتفصيل
                    </label>
                    <input 
                        required 
                        value={subData.address}
                        onChange={e => setSubData({...subData, address: e.target.value})}
                        className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                        placeholder="المدينة، الحي، اسم الشارع، رقم البناية..." 
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Phone size={16}/> رقم الهاتف
                    </label>
                    <input 
                         required
                         type="tel"
                         value={subData.phone}
                         onChange={e => setSubData({...subData, phone: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="079xxxxxxx"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Clock size={16}/> وقت التوصيل المفضل
                    </label>
                    <div className="grid grid-cols-2 gap-4">
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.MORNING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.MORNING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">صباحي</span>
                            <span className="text-xs text-gray-500">10:00 - 12:00</span>
                        </div>
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.EVENING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.EVENING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">مسائي</span>
                            <span className="text-xs text-gray-500">15:00 - 17:00</span>
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Edit3 size={16}/> ملاحظات إضافية (اختياري)
                    </label>
                    <textarea 
                         rows={3}
                         value={subData.notes}
                         onChange={e => setSubData({...subData, notes: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="هل لديك تعليمات خاصة للتوصيل أو ملاحظات غذائية؟"
                    />
                </div>

                {/* Promo Code Section */}
                <div className="bg-uh-cream/50 p-4 rounded-xl border border-uh-cream">
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Tag size={16}/> لديك كوبون خصم؟
                    </label>
                    <div className="flex gap-2">
                        <input 
                            value={promoCode}
                            onChange={e => setPromoCode(e.target.value)}
                            disabled={!!appliedPromo}
                            className="flex-1 border rounded-lg p-2 uppercase font-mono text-sm outline-none"
                            placeholder="CODE"
                        />
                        {appliedPromo ? (
                            <button type="button" onClick={() => { setAppliedPromo(null); setDiscount(0); setPromoCode(''); setPromoMessage(''); }} className="text-red-500 text-sm font-bold px-2">إلغاء</button>
                        ) : (
                            <button type="button" onClick={handleApplyPromo} className="bg-uh-dark text-white px-4 rounded-lg text-sm">تطبيق</button>
                        )}
                    </div>
                    {promoMessage && <p className={`text-xs mt-2 ${appliedPromo ? 'text-green-600' : 'text-red-500'}`}>{promoMessage}</p>}
                </div>

                {/* Pricing Summary */}
                <div className="border-t pt-4">
                    <div className="flex justify-between text-sm text-gray-600 mb-1">
                        <span>سعر الباقة</span>
                        <span>{selectedPlan.price} د.أ</span>
                    </div>
                    {discount > 0 && (
                        <div className="flex justify-between text-sm text-green-600 mb-1 font-bold">
                            <span>خصم الكوبون</span>
                            <span>- {discount.toFixed(2)} د.أ</span>
                        </div>
                    )}
                    <div className="flex justify-between text-xl font-bold text-uh-dark mt-2">
                        <span>الإجمالي</span>
                        <span>{(Math.max(0, selectedPlan.price - discount)).toFixed(2)} د.أ</span>
                    </div>
                </div>

                <div className="pt-4 flex gap-4">
                    <button type="button" onClick={() => setStep(1)} className="px-6 py-3 text-gray-500 hover:bg-gray-100 rounded-xl">رجوع</button>
                    <button type="submit" disabled={loading} className="flex-1 bg-uh-green text-white font-bold py-3 rounded-xl hover:bg-uh-greenDark shadow-lg disabled:opacity-50">
                        {loading ? 'جاري المعالجة...' : 'تأكيد الاشتراك'}
                    </button>
                </div>
            </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UserProfile, Order, Subscription, SiteContent, Meal, SubscriptionPlan, PromoCode } from '../types';
import { authService } from '../services/authService';
import { dataService } from '../services/dataService';
import { ShoppingBag, Users, FileText, Calendar, Package, LogOut, Check, X, Trash2, Plus, Settings, Key, Shield, Smartphone, Tag, LayoutList, Menu, Edit, Zap, MessageCircle, Phone, MapPin, Clock } from 'lucide-react';
import { INITIAL_USER_PROFILE, MEALS } from '../constants';
import { ImageUploader } from './ImageUploader';
import { OptimizedImage } from './OptimizedImage';

interface AdminDashboardProps {
  onLogout: () => void;
}

type Tab = 'ORDERS' | 'STORE' | 'USERS' | 'CONTENT' | 'SUBSCRIPTIONS' | 'PLANS' | 'PROMO';

export const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<Tab>('ORDERS');
  const [isSidebarOpen, setSidebarOpen] = useState(false);

  // Data State
  const [orders, setOrders] = useState<Order[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [meals, setMeals] = useState<Meal[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [promos, setPromos] = useState<PromoCode[]>([]);

  const [content, setContent] = useState<SiteContent>({
      heroTitle: '', heroSubtitle: '', heroImage: '', missionTitle: '', missionText: '', featuresList: [],
      geminiApiKey: '', contactPhone: '',
      appBannerTitle1: '', appBannerHighlight: '', appBannerText: '', appBannerImage: '',
      privacyPolicy: '', returnPolicy: '', paymentPolicy: '', socialFacebook: '', socialInstagram: '', socialTwitter: '',
      linkAndroid: '', linkIOS: ''
  });

  // Modal State
  const [showPlanModal, setShowPlanModal] = useState(false);
  const [newPlan, setNewPlan] = useState<Partial<SubscriptionPlan>>({
      title: '', price: 0, features: [], durationLabel: 'شهر', image: ''
  });
  const [planFeaturesText, setPlanFeaturesText] = useState('');

  const [showPromoModal, setShowPromoModal] = useState(false);
  const [newPromo, setNewPromo] = useState<Partial<PromoCode>>({
      code: '', discountAmount: 0, isPercentage: false, type: 'SUBSCRIPTION', isActive: true
  });

  // Meal Modal State
  const [showMealModal, setShowMealModal] = useState(false);
  const [newMeal, setNewMeal] = useState<Partial<Meal>>({
      name: '', description: '', image: '', price: 0, 
      macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
      ingredients: [], instructions: []
  });
  const [mealIngredientsText, setMealIngredientsText] = useState('');
  const [mealInstructionsText, setMealInstructionsText] = useState('');

  // Load Data
  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setOrders(await dataService.getOrders());
    setUsers(await authService.getAllUsers());
    setSubscriptions(await dataService.getSubscriptions());
    setMeals(await dataService.getMeals());
    setContent(await dataService.getContent());
    setPlans(await dataService.getSubscriptionPlans());
    setPromos(await dataService.getPromoCodes());
  };

  // Actions
  const handleUpdateOrderStatus = async (id: string, status: 'pending' | 'completed' | 'cancelled') => {
      await dataService.updateOrderStatus(id, status);
      setOrders(await dataService.getOrders());
  };

  const handleSaveContent = async (e: React.FormEvent) => {
      e.preventDefault();
      await dataService.saveContent(content);
      alert('تم حفظ المحتوى والإعدادات بنجاح');
  };

  const handleDeleteMeal = async (id: string) => {
      if(confirm('هل أنت متأكد من حذف هذه الوجبة؟')) {
          await dataService.deleteMeal(id);
          setMeals(await dataService.getMeals());
      }
  };

  const handleEditMeal = (meal: Meal) => {
      setNewMeal({...meal});
      setMealIngredientsText(meal.ingredients.join('\n'));
      setMealInstructionsText(meal.instructions.join('\n'));
      setShowMealModal(true);
  };

  const handleOpenAddMeal = () => {
      setNewMeal({
         name: '', description: '', image: '', price: 0, 
         macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
         ingredients: [], instructions: []
      });
      setMealIngredientsText('');
      setMealInstructionsText('');
      setShowMealModal(true);
  };

  const handleSaveMeal = async () => {
      if (!newMeal.name || !newMeal.price) {
          alert('الرجاء إدخال اسم الوجبة والسعر');
          return;
      }

      // Check if updating existing or creating new
      const idToUse = newMeal.id || `m_${Date.now()}`;

      const mealToSave: Meal = {
          id: idToUse,
          name: newMeal.name,
          description: newMeal.description || '',
          image: newMeal.image || 'https://picsum.photos/400/300',
          price: Number(newMeal.price),
          macros: newMeal.macros || { protein: 0, carbs: 0, fats: 0, calories: 0 },
          ingredients: mealIngredientsText.split('\n').filter(i => i.trim()),
          instructions: mealInstructionsText.split('\n').filter(i => i.trim())
      };

      try {
          await dataService.addMeal(mealToSave);
          alert(newMeal.id ? 'تم تحديث الوجبة بنجاح!' : 'تم إضافة الوجبة بنجاح!');
          setMeals(await dataService.getMeals());
          setShowMealModal(false);
          setNewMeal({
             name: '', description: '', image: '', price: 0, 
             macros: { protein: 0, carbs: 0, fats: 0, calories: 0 },
             ingredients: [], instructions: []
          });
          setMealIngredientsText('');
          setMealInstructionsText('');
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الوجبة');
      }
  };

  // --- PLAN MANAGEMENT FUNCTIONS ---

  const handleOpenAddPlan = () => {
      setNewPlan({ title: '', price: 0, features: [], durationLabel: 'شهر', image: '' });
      setPlanFeaturesText('');
      setShowPlanModal(true);
  };

  const handleEditPlan = (plan: SubscriptionPlan) => {
      setNewPlan({ ...plan });
      setPlanFeaturesText(plan.features.join('\n'));
      setShowPlanModal(true);
  };

  const handleSavePlan = async () => {
      if (!newPlan.title) {
          alert('الرجاء إدخال اسم الباقة');
          return;
      }
      if (!newPlan.price || Number(newPlan.price) <= 0) {
          alert('الرجاء إدخال سعر صحيح للباقة');
          return;
      }

      // Use existing ID if editing, or create new
      const idToUse = newPlan.id || `plan_${Date.now()}`;

      const planToSave: SubscriptionPlan = {
          id: idToUse,
          title: newPlan.title,
          price: Number(newPlan.price),
          durationLabel: newPlan.durationLabel || 'شهر',
          image: newPlan.image || 'https://images.unsplash.com/photo-1543362906-ac1b48263852?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
          features: planFeaturesText.split('\n').filter(f => f.trim() !== ''),
          isPopular: newPlan.isPopular || false
      };

      try {
          await dataService.saveSubscriptionPlan(planToSave);
          alert(newPlan.id ? 'تم تحديث الباقة بنجاح!' : 'تم إضافة الباقة بنجاح!');
          setPlans(await dataService.getSubscriptionPlans());
          setShowPlanModal(false);
          setNewPlan({ title: '', price: 0, features: [], durationLabel: 'شهر', image: '' });
          setPlanFeaturesText('');
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الباقة، يرجى المحاولة مرة أخرى.');
      }
  };

  const handleDeletePlan = async (id: string) => {
      if(confirm('حذف هذه الباقة؟')) {
          await dataService.deleteSubscriptionPlan(id);
          setPlans(await dataService.getSubscriptionPlans());
      }
  };

  // --- PROMO MANAGEMENT FUNCTIONS ---

  const handleSavePromo = async () => {
      if (!newPromo.code) {
          alert('الرجاء إدخال كود الخصم');
          return;
      }
      if (!newPromo.discountAmount || Number(newPromo.discountAmount) <= 0) {
          alert('الرجاء إدخال قيمة الخصم');
          return;
      }

      const promoToSave: PromoCode = {
          id: `promo_${Date.now()}`,
          code: newPromo.code.toUpperCase(),
          discountAmount: Number(newPromo.discountAmount),
          type: newPromo.type as 'MEALS' | 'SUBSCRIPTION',
          isPercentage: newPromo.isPercentage || false,
          isActive: true
      };

      try {
          await dataService.savePromoCode(promoToSave);
          alert('تم إضافة كود الخصم بنجاح!');
          setPromos(await dataService.getPromoCodes());
          setShowPromoModal(false);
          setNewPromo({ code: '', discountAmount: 0, isPercentage: false, type: 'SUBSCRIPTION', isActive: true });
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الكود.');
      }
  };

  const handleDeletePromo = async (id: string) => {
      if(confirm('حذف هذا الكود؟')) {
          await dataService.deletePromoCode(id);
          setPromos(await dataService.getPromoCodes());
      }
  };

  // Render Helpers
  const renderSidebarItem = (tab: Tab, label: string, Icon: any) => (
      <button 
        onClick={() => { setActiveTab(tab); setSidebarOpen(false); }}
        className={`flex items-center gap-3 w-full p-3 rounded-lg transition ${activeTab === tab ? 'bg-uh-gold text-uh-dark font-bold' : 'text-gray-400 hover:bg-white/10 hover:text-white'}`}
      >
          <Icon size={20} />
          <span>{label}</span>
      </button>
  );

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden font-arabic" dir="rtl">
      {/* Sidebar (Desktop) */}
      <aside className={`fixed inset-y-0 right-0 z-50 w-64 bg-uh-dark text-white transform transition-transform duration-300 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
         <div className="p-6 border-b border-white/10 flex justify-between items-center">
             <h2 className="text-xl font-brand font-bold text-white">لوحة التحكم</h2>
             <button onClick={() => setSidebarOpen(false)} className="md:hidden text-gray-400"><X /></button>
         </div>
         <nav className="p-4 space-y-2 overflow-y-auto h-[calc(100vh-80px)]">
             {renderSidebarItem('ORDERS', 'الطلبات', ShoppingBag)}
             {renderSidebarItem('SUBSCRIPTIONS', 'الاشتراكات', Calendar)}
             {renderSidebarItem('STORE', 'إدارة الوجبات', Package)}
