                                onChange={e => setNewPromo({...newPromo, discountAmount: Number(e.target.value)})}
                             />
                             <div className="w-1/2 flex items-center gap-2 border p-3 rounded-lg">
                                <input 
                                    type="checkbox" 
                                    checked={newPromo.isPercentage}
                                    onChange={e => setNewPromo({...newPromo, isPercentage: e.target.checked})}
                                />
                                <span className="text-sm">نسبة مئوية؟</span>
                             </div>
                          </div>
                          <select 
                            className="w-full border p-3 rounded-lg"
                            value={newPromo.type}
                            onChange={e => setNewPromo({...newPromo, type: e.target.value as any})}
                          >
                              <option value="SUBSCRIPTION">خاص بالاشتراكات</option>
                              <option value="MEALS">خاص بالوجبات (المتجر)</option>
                          </select>
                          <button onClick={handleSavePromo} className="w-full bg-uh-green text-white font-bold py-3 rounded-lg">حفظ الكود</button>
                      </div>
                  </div>
              </div>
          )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Home } from './components/Home';
import { Onboarding } from './components/Onboarding';
import { Store } from './components/Store';
import { Profile } from './components/Profile';
import { Subscription } from './components/Subscription';
import { Login } from './components/Login';
import { MealDetail } from './components/MealDetail';
import { Cart } from './components/Cart';
import { AdminDashboard } from './components/AdminDashboard';
import { ChatWidget } from './components/ChatWidget';
import { StaticPage } from './components/StaticPage';
import { UserProfile, PageView, Meal, CartItem, SiteContent } from './types';
import { INITIAL_USER_PROFILE } from './constants';
import { dataService } from './services/dataService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<PageView>('HOME');
  const [user, setUser] = useState<UserProfile>(INITIAL_USER_PROFILE);
  const [selectedMeal, setSelectedMeal] = useState<Meal | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [content, setContent] = useState<SiteContent | null>(null);
  const [initialPlanId, setInitialPlanId] = useState<string | null>(null);

  // Fetch content on mount
  useEffect(() => {
    const fetchContent = async () => {
        const c = await dataService.getContent();
        setContent(c);
    };
    fetchContent();
  }, []);

  // Handle Deep Linking (URL Query Params) on Mount
  useEffect(() => {
      const handleDeepLinks = async () => {
          const params = new URLSearchParams(window.location.search);
          const mealId = params.get('mealId');
          const planId = params.get('planId');

          if (mealId) {
              const allMeals = await dataService.getMeals();
              const meal = allMeals.find(m => m.id === mealId);
              if (meal) {
                  setSelectedMeal(meal);
                  setCurrentView('MEAL_DETAIL');
              }
          } else if (planId) {
              setInitialPlanId(planId);
              setCurrentView('SUBSCRIPTION');
          }
      };

      handleDeepLinks();
  }, []);

  // Reset scroll on view change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentView]);

  // Auth Handlers
  const handleLogin = (loggedInUser: UserProfile) => {
    setUser(loggedInUser);
    if (loggedInUser.isAdmin) {
        setCurrentView('ADMIN');
    } else {
        setCurrentView('PROFILE');
    }
  };

  const handleProfileCreated = (profile: UserProfile) => {
    setUser(profile);
    setCurrentView('PROFILE');
  };

  const handleLogout = () => {
    setUser(INITIAL_USER_PROFILE);
    setCurrentView('HOME');
    setCart([]); // Optional: Clear cart on logout
  };

  // Cart Handlers
  const handleAddToCart = (meal: Meal) => {
    setCart(prev => {
        const existing = prev.find(item => item.id === meal.id);
        if (existing) {
            return prev.map(item => item.id === meal.id ? { ...item, quantity: item.quantity + 1 } : item);
        }
        return [...prev, { ...meal, quantity: 1 }];
    });
    // Optional: could show toast notification
  };

  const handleUpdateCartQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
        if (item.id === id) {
            const newQty = item.quantity + delta;
            return newQty > 0 ? { ...item, quantity: newQty } : item;
        }
        return item;
    }));
  };

  const handleRemoveFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleClearCart = () => {
      setCart([]);
  };

  // Navigation Handlers
  const handleMealClick = async (mealId: string) => {
    const allMeals = await dataService.getMeals(); // Get latest from service (async)
    const meal = allMeals.find(m => m.id === mealId);
    if (meal) {
      setSelectedMeal(meal);
      setCurrentView('MEAL_DETAIL');
    }
  };

  const renderView = () => {
    // If content hasn't loaded yet, we can show a loader or fallback
    // But StaticPage handles inputs, so if null, we just pass defaults inside logic or ensure content is not null
    const safeContent = content || {
        privacyPolicy: '',
        returnPolicy: '',
        paymentPolicy: '',
        heroTitle: '', heroSubtitle: '', heroImage: '', missionTitle: '', missionText: '', socialFacebook: '', socialInstagram: '', socialTwitter: ''
    };

    switch (currentView) {
      case 'HOME':
        // Modified: onStart now goes directly to ONBOARDING for new users instead of Login
        return <Home onStart={() => setCurrentView(user.hasProfile ? 'PROFILE' : 'ONBOARDING')} />;
      case 'LOGIN':
        return <Login onLogin={handleLogin} onGoToSignup={() => setCurrentView('ONBOARDING')} />;
      case 'ONBOARDING':
        return <Onboarding onComplete={handleProfileCreated} />;
      case 'STORE':
        return <Store onMealClick={handleMealClick} onAddToCart={handleAddToCart} />;
      case 'PROFILE':
         // If user tries to access profile without login, send to login
        if (!user.hasProfile) {
            return <Login onLogin={handleLogin} onGoToSignup={() => setCurrentView('ONBOARDING')} />;
        }
        return <Profile user={user} onMealClick={handleMealClick} onAddToCart={handleAddToCart} />;
      case 'SUBSCRIPTION':
        return <Subscription initialPlanId={initialPlanId} />;
      case 'CART':
        return (
            <Cart 
                items={cart} 
                user={user}
                onUpdateQuantity={handleUpdateCartQuantity}
                onRemoveItem={handleRemoveFromCart}
                onClearCart={handleClearCart}
                onBackToStore={() => setCurrentView('STORE')}
            />
        );
      case 'MEAL_DETAIL':
        return selectedMeal ? (
            <MealDetail 
                meal={selectedMeal} 
                onBack={() => setCurrentView('STORE')} 
                onAddToCart={(meal) => {
                    handleAddToCart(meal);
                    setCurrentView('CART'); // Optionally go straight to cart
                }}
            />
        ) : <Store onMealClick={handleMealClick} onAddToCart={handleAddToCart} />;

      // Legal Pages
      case 'PRIVACY_POLICY':
        return <StaticPage title="سياسة الاستخدام والخصوصية" content={safeContent.privacyPolicy} type="PRIVACY" onBack={() => setCurrentView('HOME')} />;
      case 'RETURN_POLICY':
        return <StaticPage title="سياسة الإرجاع" content={safeContent.returnPolicy} type="RETURN" onBack={() => setCurrentView('HOME')} />;
      case 'PAYMENT_POLICY':
        return <StaticPage title="نظام الدفع" content={safeContent.paymentPolicy} type="PAYMENT" onBack={() => setCurrentView('HOME')} />;

      case 'ADMIN':
        if (!user.isAdmin) return <Home onStart={() => setCurrentView('LOGIN')} />;
        return <AdminDashboard onLogout={handleLogout} />;
      default:
        return <Home onStart={() => setCurrentView('LOGIN')} />;
    }
  };

  const cartItemCount = cart.reduce((sum, item) => sum + item.quantity, 0);

  // If Admin, render Dashboard without Layout wrapper (full screen dashboard)
  if (currentView === 'ADMIN') {
      return renderView();
  }

  // Regular View
  return (
    <>
      <Layout 
          setView={setCurrentView} 
          currentView={currentView} 
          isLoggedIn={user.hasProfile} 
          onLogout={handleLogout}
          cartItemCount={cartItemCount}
      >
        {renderView()}
      </Layout>
      {/* ChatWidget outside Layout to ensure fixed positioning works correctly relative to viewport */}
      <ChatWidget />
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Subscription as SubscriptionModel, DeliverySlot, SubscriptionPlan } from '../types';
import { dataService } from '../services/dataService';
import { Check, Clock, MapPin, Truck, Tag, Edit3, Phone } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface SubscriptionProps {
    initialPlanId?: string | null;
}

export const Subscription: React.FC<SubscriptionProps> = ({ initialPlanId }) => {
  const [step, setStep] = useState(1);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [selectedPlanId, setSelectedPlanId] = useState<string | null>(null);

  const [subData, setSubData] = useState<Partial<SubscriptionModel>>({
    deliverySlot: DeliverySlot.MORNING,
    address: '',
    phone: '',
    notes: ''
  });

  // Promo Logic
  const [promoCode, setPromoCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [appliedPromo, setAppliedPromo] = useState<string | null>(null);
  const [promoMessage, setPromoMessage] = useState('');

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchPlans = async () => {
        setPlans(await dataService.getSubscriptionPlans());
    };
    fetchPlans();
  }, []);

  // Handle Deep Linking / Initial Plan
  useEffect(() => {
      if (initialPlanId && plans.length > 0) {
          const exists = plans.some(p => p.id === initialPlanId);
          if (exists) {
              handleSelectPlan(initialPlanId);
          }
      }
  }, [initialPlanId, plans]);

  const handleSelectPlan = (id: string) => {
    setSelectedPlanId(id);
    setSubData(prev => ({ ...prev, duration: id }));
    setStep(2);
    // Reset Promo when changing plans
    setDiscount(0);
    setAppliedPromo(null);
    setPromoCode('');
    setPromoMessage('');
  };

  const handleApplyPromo = async () => {
      if (!promoCode) return;

      const promo = await dataService.verifyPromoCode(promoCode.toUpperCase(), 'SUBSCRIPTION');
      if (promo) {
          const selectedPlan = plans.find(p => p.id === selectedPlanId);
          if (selectedPlan) {
             let discVal = 0;
             if (promo.isPercentage) {
                 discVal = selectedPlan.price * (promo.discountAmount / 100);
             } else {
                 discVal = promo.discountAmount;
             }
             setDiscount(discVal);
             setAppliedPromo(promo.code);
             setPromoMessage('تم تفعيل الخصم بنجاح! 🎉');
          }
      } else {
          setPromoMessage('كود الخصم غير صالح أو غير مخصص للاشتراكات ❌');
          setDiscount(0);
          setAppliedPromo(null);
      }
  };

  const handleDetailsSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const selectedPlan = plans.find(p => p.id === selectedPlanId);

    if(subData.address && subData.phone && selectedPlanId && subData.deliverySlot && selectedPlan) {
        const finalPrice = Math.max(0, selectedPlan.price - discount);

        try {
            await dataService.saveSubscription({
                duration: selectedPlan.durationLabel, // Store label for readability
                deliverySlot: subData.deliverySlot,
                address: subData.address,
                phone: subData.phone,
                notes: subData.notes, // Save notes
                date: new Date().toISOString(),
                planTitle: selectedPlan.title,
                pricePaid: finalPrice
            });
            alert('تم استلام طلب الاشتراك بنجاح! سيتواصل معك فريقنا قريباً.');
            setStep(1);
            setSelectedPlanId(null);
            setSubData({ deliverySlot: DeliverySlot.MORNING, address: '', phone: '', notes: '' });
        } catch (error) {
            console.error(error);
            alert("عذراً، حدث خطأ أثناء حفظ الاشتراك في قاعدة البيانات. يرجى المحاولة مرة أخرى.");
        }
    }

    setLoading(false);
  };

  const selectedPlan = plans.find(p => p.id === selectedPlanId);

  return (
    <div className="max-w-4xl mx-auto py-8 mb-20 md:mb-0">
      <div className="text-center mb-12">
        <h2 className="text-3xl font-brand text-uh-dark">اختر باقتك</h2>
        <p className="text-gray-500">وجبات صحية تصلك إلى باب بيتك</p>
      </div>

      {step === 1 && (
        <div className="grid md:grid-cols-2 gap-8 animate-fade-in">
          {plans.map(plan => (
            <div key={plan.id} className="bg-white rounded-3xl shadow-lg border-2 border-transparent hover:border-uh-green transition relative overflow-hidden group flex flex-col">
              {plan.image && (
                <div className="h-48 overflow-hidden">
                    <OptimizedImage src={plan.image} alt={plan.title} width={600} className="w-full h-full group-hover:scale-105 transition" />
                </div>
              )}

              {plan.isPopular && (
                  <div className="absolute top-0 right-0 bg-uh-gold text-uh-dark px-4 py-1 rounded-bl-xl text-sm font-bold shadow-sm z-10">الأكثر طلباً</div>
              )}

              <div className="p-8 flex flex-col flex-1">
                <h3 className="text-2xl font-bold mb-2 text-uh-dark">{plan.title}</h3>
                <div className="text-4xl font-brand text-uh-greenDark mb-6">{plan.price} <span className="text-lg text-gray-400">د.أ</span> <span className="text-sm text-gray-400 font-sans">/ {plan.durationLabel}</span></div>

                <ul className="space-y-4 mb-8 flex-1">
                    {plan.features.map((f, i) => (
                        <li key={i} className="flex items-center gap-3 text-gray-600">
                            <Check className="text-uh-green" size={18} />
                            {f}
                        </li>
                    ))}
                </ul>
                <button 
                    onClick={() => handleSelectPlan(plan.id)}
                    className="w-full bg-uh-dark text-white py-3 rounded-xl font-bold hover:bg-black transition"
                >
                    اختيار الباقة
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {step === 2 && selectedPlan && (
        <div className="bg-white rounded-3xl shadow-xl p-8 max-w-2xl mx-auto animate-fade-in">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                <Truck className="text-uh-gold" />
                تفاصيل الاشتراك: <span className="text-uh-green">{selectedPlan.title}</span>
            </h3>

            <form onSubmit={handleDetailsSubmit} className="space-y-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <MapPin size={16}/> عنوان التوصيل بالتفصيل
                    </label>
                    <input 
                        required 
                        value={subData.address}
                        onChange={e => setSubData({...subData, address: e.target.value})}
                        className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                        placeholder="المدينة، الحي، اسم الشارع، رقم البناية..." 
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Phone size={16}/> رقم الهاتف
                    </label>
                    <input 
                         required
                         type="tel"
                         value={subData.phone}
                         onChange={e => setSubData({...subData, phone: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="079xxxxxxx"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Clock size={16}/> وقت التوصيل المفضل
                    </label>
                    <div className="grid grid-cols-2 gap-4">
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.MORNING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.MORNING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">صباحي</span>
                            <span className="text-xs text-gray-500">10:00 - 12:00</span>
                        </div>
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.EVENING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.EVENING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">مسائي</span>
                            <span className="text-xs text-gray-500">15:00 - 17:00</span>
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Edit3 size={16}/> ملاحظات إضافية (اختياري)
                    </label>
                    <textarea 
                         rows={3}
                         value={subData.notes}
                         onChange={e => setSubData({...subData, notes: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="هل لديك تعليمات خاصة للتوصيل أو ملاحظات غذائية؟"
                    />
                </div>

                {/* Promo Code Section */}
                <div className="bg-uh-cream/50 p-4 rounded-xl border border-uh-cream">
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Tag size={16}/> لديك كوبون خصم؟
                    </label>
                    <div className="flex gap-2">
                        <input 
                            value={promoCode}
                            onChange={e => setPromoCode(e.target.value)}
                            disabled={!!appliedPromo}
                            className="flex-1 border rounded-lg p-2 uppercase font-mono text-sm outline-none"
                            placeholder="CODE"
                        />
                        {appliedPromo ? (
                            <button type="button" onClick={() => { setAppliedPromo(null); setDiscount(0); setPromoCode(''); setPromoMessage(''); }} className="text-red-500 text-sm font-bold px-2">إلغاء</button>
                        ) : (
                            <button type="button" onClick={handleApplyPromo} className="bg-uh-dark text-white px-4 rounded-lg text-sm">تطبيق</button>
                        )}
                    </div>
                    {promoMessage && <p className={`text-xs mt-2 ${appliedPromo ? 'text-green-600' : 'text-red-500'}`}>{promoMessage}</p>}
                </div>

                {/* Pricing Summary */}
                <div className="border-t pt-4">
                    <div className="flex justify-between text-sm text-gray-600 mb-1">
                        <span>سعر الباقة</span>
                        <span>{selectedPlan.price} د.أ</span>
                    </div>
                    {discount > 0 && (
                        <div className="flex justify-between text-sm text-green-600 mb-1 font-bold">
                            <span>خصم الكوبون</span>
                            <span>- {discount.toFixed(2)} د.أ</span>
                        </div>
                    )}
                    <div className="flex justify-between text-xl font-bold text-uh-dark mt-2">
                        <span>الإجمالي</span>
                        <span>{(Math.max(0, selectedPlan.price - discount)).toFixed(2)} د.أ</span>
                    </div>
                </div>

                <div className="pt-4 flex gap-4">
                    <button type="button" onClick={() => setStep(1)} className="px-6 py-3 text-gray-500 hover:bg-gray-100 rounded-xl">رجوع</button>
                    <button type="submit" disabled={loading} className="flex-1 bg-uh-green text-white font-bold py-3 rounded-xl hover:bg-uh-greenDark shadow-lg disabled:opacity-50">
                        {loading ? 'جاري المعالجة...' : 'تأكيد الاشتراك'}
                    </button>
                </div>
            </form>
        </div>
      )}
    </div>
  );
};

