                                                   sub.status === 'out-for-delivery' ? 'في الطريق' : 'بانتظار التجهيز'}
                                              </span>
                                          </div>

                                          <div className="space-y-2">
                                              <div className="flex justify-between text-xs">
                                                  <span>خروج من المطعم:</span>
                                                  <span className="font-mono font-bold text-uh-dark">{sub.departureTime || '--:--'}</span>
                                              </div>
                                              <div className="flex justify-between text-xs">
                                                  <span>وصول للزبون:</span>
                                                  <span className="font-mono font-bold text-uh-dark">{sub.arrivalTime || '--:--'}</span>
                                              </div>
                                          </div>
                                      </div>

                                      <div className="grid grid-cols-2 gap-2 mt-6">
                                          {sub.status !== 'delivered' && (
                                              <>
                                                {sub.status === 'active' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(sub.id, { status: 'out-for-delivery', departureTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}) })}
                                                        className="col-span-2 bg-uh-dark text-white py-2 rounded-lg font-bold hover:bg-black transition flex items-center justify-center gap-2"
                                                    >
                                                        <Truck size={16}/> خروج الطلب
                                                    </button>
                                                )}
                                                {sub.status === 'out-for-delivery' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(sub.id, { status: 'delivered', arrivalTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}), deliveredCount: (sub.deliveredCount || 0) + 1 })}
                                                        className="col-span-2 bg-uh-green text-white py-2 rounded-lg font-bold hover:bg-uh-greenDark transition flex items-center justify-center gap-2"
                                                    >
                                                        <CheckCircle size={16}/> تأكيد الاستلام
                                                    </button>
                                                )}
                                                <button 
                                                    onClick={() => handlePostpone(sub)}
                                                    className="col-span-2 border-2 border-red-200 text-red-500 py-2 rounded-lg font-bold hover:bg-red-50 transition flex items-center justify-center gap-2"
                                                >
                                                    <RefreshCcw size={16}/> تأجيل الوجبة
                                                </button>
                                              </>
                                          )}
                                          {sub.status === 'delivered' && (
                                              <div className="col-span-2 bg-green-50 text-green-700 py-2 rounded-lg text-center font-bold text-sm">
                                                  تمت خدمة هذا الاشتراك اليوم ✅
                                              </div>
                                          )}
                                      </div>
                                  </div>

                              </div>
                          </div>
                      );
                  })}
                  {filteredSubs.length === 0 && (
                      <div className="bg-white p-10 rounded-2xl border border-dashed border-gray-300 text-center text-gray-400">
                          لا توجد اشتراكات مطابقة لهذا التصنيف
                      </div>
                  )}
              </div>
          )}
      </main>

      {/* Footer Info */}
      <footer className="bg-white border-t border-gray-200 p-4 text-center text-xs text-gray-400">
          جميع البيانات يتم حفظها وتحديثها فورياً في قاعدة بيانات Uncle Healthy
      </footer>
    </div>
  );
};

