import React, { useState, useEffect } from 'react';
import { Subscription as SubscriptionModel, DeliverySlot, SubscriptionPlan } from '../types';
import { dataService } from '../services/dataService';
import { Check, Clock, MapPin, Truck, Tag, Edit3, Phone } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface SubscriptionProps {
    initialPlanId?: string | null;
}

export const Subscription: React.FC<SubscriptionProps> = ({ initialPlanId }) => {
  const [step, setStep] = useState(1);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [selectedPlanId, setSelectedPlanId] = useState<string | null>(null);

  const [subData, setSubData] = useState<Partial<SubscriptionModel>>({
    deliverySlot: DeliverySlot.MORNING,
    address: '',
    phone: '',
    notes: ''
  });

  // Promo Logic
  const [promoCode, setPromoCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [appliedPromo, setAppliedPromo] = useState<string | null>(null);
  const [promoMessage, setPromoMessage] = useState('');

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchPlans = async () => {
        setPlans(await dataService.getSubscriptionPlans());
    };
    fetchPlans();
  }, []);

  // Handle Deep Linking / Initial Plan
  useEffect(() => {
      if (initialPlanId && plans.length > 0) {
          const exists = plans.some(p => p.id === initialPlanId);
          if (exists) {
              handleSelectPlan(initialPlanId);
          }
      }
  }, [initialPlanId, plans]);

  const handleSelectPlan = (id: string) => {
    setSelectedPlanId(id);
    setSubData(prev => ({ ...prev, duration: id }));
    setStep(2);
    // Reset Promo when changing plans
    setDiscount(0);
    setAppliedPromo(null);
    setPromoCode('');
    setPromoMessage('');
  };

  const handleApplyPromo = async () => {
      if (!promoCode) return;

      const promo = await dataService.verifyPromoCode(promoCode.toUpperCase(), 'SUBSCRIPTION');
      if (promo) {
          const selectedPlan = plans.find(p => p.id === selectedPlanId);
          if (selectedPlan) {
             let discVal = 0;
             if (promo.isPercentage) {
                 discVal = selectedPlan.price * (promo.discountAmount / 100);
             } else {
                 discVal = promo.discountAmount;
             }
             setDiscount(discVal);
             setAppliedPromo(promo.code);
             setPromoMessage('تم تفعيل الخصم بنجاح! 🎉');
          }
      } else {
          setPromoMessage('كود الخصم غير صالح أو غير مخصص للاشتراكات ❌');
          setDiscount(0);
          setAppliedPromo(null);
      }
  };

  const handleDetailsSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const selectedPlan = plans.find(p => p.id === selectedPlanId);

    if(subData.address && subData.phone && selectedPlanId && subData.deliverySlot && selectedPlan) {
        const finalPrice = Math.max(0, selectedPlan.price - discount);

        try {
            // Added 'id' and 'status' to satisfy the 'Subscription' interface requirements.
            // dataService.saveSubscription will handle real ID generation and status initialization.
            await dataService.saveSubscription({
                id: '', // Will be updated in dataService
                status: 'active', // Default initial status
                duration: selectedPlan.durationLabel, // Store label for readability
                deliverySlot: subData.deliverySlot,
                address: subData.address,
                phone: subData.phone,
                notes: subData.notes, // Save notes
                date: new Date().toISOString(),
                planTitle: selectedPlan.title,
                pricePaid: finalPrice
            });
            alert('تم استلام طلب الاشتراك بنجاح! سيتواصل معك فريقنا قريباً.');
            setStep(1);
            setSelectedPlanId(null);
            setSubData({ deliverySlot: DeliverySlot.MORNING, address: '', phone: '', notes: '' });
        } catch (error) {
            console.error(error);
            alert("عذراً، حدث خطأ أثناء حفظ الاشتراك في قاعدة البيانات. يرجى المحاولة مرة أخرى.");
        }
    }

    setLoading(false);
  };

  const selectedPlan = plans.find(p => p.id === selectedPlanId);

  return (
    <div className="max-w-4xl mx-auto py-8 mb-20 md:mb-0">
      <div className="text-center mb-12">
        <h2 className="text-3xl font-brand text-uh-dark">اختر باقتك</h2>
        <p className="text-gray-500">وجبات صحية تصلك إلى باب بيتك</p>
      </div>

      {step === 1 && (
        <div className="grid md:grid-cols-2 gap-8 animate-fade-in">
          {plans.map(plan => (
            <div key={plan.id} className="bg-white rounded-3xl shadow-lg border-2 border-transparent hover:border-uh-green transition relative overflow-hidden group flex flex-col">
              {plan.image && (
                <div className="h-48 overflow-hidden">
                    <OptimizedImage src={plan.image} alt={plan.title} width={600} className="w-full h-full group-hover:scale-105 transition" />
                </div>
              )}

              {plan.isPopular && (
                  <div className="absolute top-0 right-0 bg-uh-gold text-uh-dark px-4 py-1 rounded-bl-xl text-sm font-bold shadow-sm z-10">الأكثر طلباً</div>
              )}

              <div className="p-8 flex flex-col flex-1">
                <h3 className="text-2xl font-bold mb-2 text-uh-dark">{plan.title}</h3>
                <div className="text-4xl font-brand text-uh-greenDark mb-6">{plan.price} <span className="text-lg text-gray-400">د.أ</span> <span className="text-sm text-gray-400 font-sans">/ {plan.durationLabel}</span></div>

                <ul className="space-y-4 mb-8 flex-1">
                    {plan.features.map((f, i) => (
                        <li key={i} className="flex items-center gap-3 text-gray-600">
                            <Check className="text-uh-green" size={18} />
                            {f}
                        </li>
                    ))}
                </ul>
                <button 
                    onClick={() => handleSelectPlan(plan.id)}
                    className="w-full bg-uh-dark text-white py-3 rounded-xl font-bold hover:bg-black transition"
                >
                    اختيار الباقة
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {step === 2 && selectedPlan && (
        <div className="bg-white rounded-3xl shadow-xl p-8 max-w-2xl mx-auto animate-fade-in">
            <h3 className="text-xl font-bold mb-6 flex items-center gap-2">
                <Truck className="text-uh-gold" />
                تفاصيل الاشتراك: <span className="text-uh-green">{selectedPlan.title}</span>
            </h3>

            <form onSubmit={handleDetailsSubmit} className="space-y-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <MapPin size={16}/> عنوان التوصيل بالتفصيل
                    </label>
                    <input 
                        required 
                        value={subData.address}
                        onChange={e => setSubData({...subData, address: e.target.value})}
                        className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                        placeholder="المدينة، الحي، اسم الشارع، رقم البناية..." 
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Phone size={16}/> رقم الهاتف
                    </label>
                    <input 
                         required
                         type="tel"
                         value={subData.phone}
                         onChange={e => setSubData({...subData, phone: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="079xxxxxxx"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Clock size={16}/> وقت التوصيل المفضل
                    </label>
                    <div className="grid grid-cols-2 gap-4">
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.MORNING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.MORNING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">صباحي</span>
                            <span className="text-xs text-gray-500">10:00 - 12:00</span>
                        </div>
                        <div 
                            onClick={() => setSubData({...subData, deliverySlot: DeliverySlot.EVENING})}
                            className={`p-4 border rounded-xl cursor-pointer text-center transition ${subData.deliverySlot === DeliverySlot.EVENING ? 'border-uh-green bg-green-50 text-uh-greenDark font-bold' : 'hover:bg-gray-50'}`}
                        >
                            <span className="block font-bold">مسائي</span>
                            <span className="text-xs text-gray-500">15:00 - 17:00</span>
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Edit3 size={16}/> ملاحظات إضافية (اختياري)
                    </label>
                    <textarea 
                         rows={3}
                         value={subData.notes}
                         onChange={e => setSubData({...subData, notes: e.target.value})}
                         className="w-full border rounded-lg p-3 bg-gray-50 focus:ring-2 focus:ring-uh-green outline-none" 
                         placeholder="هل لديك تعليمات خاصة للتوصيل أو ملاحظات غذائية؟"
                    />
                </div>

                {/* Promo Code Section */}
                <div className="bg-uh-cream/50 p-4 rounded-xl border border-uh-cream">
                    <label className="block text-sm font-medium text-gray-700 mb-2 flex items-center gap-2">
                        <Tag size={16}/> لديك كوبون خصم؟
                    </label>
                    <div className="flex gap-2">
                        <input 
                            value={promoCode}
                            onChange={e => setPromoCode(e.target.value)}
                            disabled={!!appliedPromo}
                            className="flex-1 border rounded-lg p-2 uppercase font-mono text-sm outline-none"
                            placeholder="CODE"
                        />
                        {appliedPromo ? (
                            <button type="button" onClick={() => { setAppliedPromo(null); setDiscount(0); setPromoCode(''); setPromoMessage(''); }} className="text-red-500 text-sm font-bold px-2">إلغاء</button>
                        ) : (
                            <button type="button" onClick={handleApplyPromo} className="bg-uh-dark text-white px-4 rounded-lg text-sm">تطبيق</button>
                        )}
                    </div>
                    {promoMessage && <p className={`text-xs mt-2 ${appliedPromo ? 'text-green-600' : 'text-red-500'}`}>{promoMessage}</p>}
                </div>

                {/* Pricing Summary */}
                <div className="border-t pt-4">
                    <div className="flex justify-between text-sm text-gray-600 mb-1">
                        <span>سعر الباقة</span>
                        <span>{selectedPlan.price} د.أ</span>
                    </div>
                    {discount > 0 && (
                        <div className="flex justify-between text-sm text-green-600 mb-1 font-bold">
                            <span>خصم الكوبون</span>
                            <span>- {discount.toFixed(2)} د.أ</span>
                        </div>
                    )}
                    <div className="flex justify-between text-xl font-bold text-uh-dark mt-2">
                        <span>الإجمالي</span>
                        <span>{(Math.max(0, selectedPlan.price - discount)).toFixed(2)} د.أ</span>
                    </div>
                </div>

                <div className="pt-4 flex gap-4">
                    <button type="button" onClick={() => setStep(1)} className="px-6 py-3 text-gray-500 hover:bg-gray-100 rounded-xl">رجوع</button>
                    <button type="submit" disabled={loading} className="flex-1 bg-uh-green text-white font-bold py-3 rounded-xl hover:bg-uh-greenDark shadow-lg disabled:opacity-50">
                        {loading ? 'جاري المعالجة...' : 'تأكيد الاشتراك'}
                    </button>
                </div>
            </form>
        </div>
      )}
    </div>
  );
};

import { Order, Subscription, SiteContent, Meal, SubscriptionPlan, PromoCode, AnalyticsData } from '../types';
import { MEALS } from '../constants';
import { db } from './firebase';
import { collection, getDocs, doc, setDoc, updateDoc, deleteDoc, getDoc, increment } from 'firebase/firestore';

// Local cache only for configuration items (Plans/Promos/Content)
let localPlans: SubscriptionPlan[] = [];
let localPromos: PromoCode[] = [];

export const dataService = {
  // Orders
  getOrders: async (): Promise<Order[]> => {
    try {
      const orders: Order[] = [];
      const querySnapshot = await getDocs(collection(db, "orders"));
      querySnapshot.forEach((doc) => {
        orders.push(doc.data() as Order);
      });
      return orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    } catch (e) {
      console.error("Failed to fetch orders from DB:", e);
      return [];
    }
  },

  saveOrder: async (order: Order) => {
    await setDoc(doc(db, "orders", order.id), order);
  },

  updateOrderStatus: async (id: string, status: 'pending' | 'completed' | 'cancelled') => {
    const orderRef = doc(db, "orders", id);
    await updateDoc(orderRef, { status: status });
  },

  // Subscriptions
  getSubscriptions: async (): Promise<Subscription[]> => {
    try {
      const subs: Subscription[] = [];
      const querySnapshot = await getDocs(collection(db, "subscriptions"));
      querySnapshot.forEach((doc) => {
        subs.push(doc.data() as Subscription);
      });
      return subs.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    } catch (e) {
      console.error("Failed to fetch subscriptions from DB:", e);
      return [];
    }
  },

  saveSubscription: async (sub: Subscription) => {
    const id = sub.id || `sub_${Date.now()}`;
    const subWithId = { ...sub, id, status: 'active', deliveredCount: 0, postponedCount: 0 };
    await setDoc(doc(db, "subscriptions", id), subWithId);
  },

  updateSubscription: async (id: string, updates: Partial<Subscription>) => {
    const subRef = doc(db, "subscriptions", id);
    await updateDoc(subRef, updates);
  },

  // Content
  getContent: async (): Promise<SiteContent> => {
    const defaults: SiteContent = {
        heroTitle: 'نمط حياة خفيف وصحي للجميع',
        heroSubtitle: 'انكل هيلثي هو وجهتك الأولى للوجبات الصحية الفاخرة. نجمع بين الذكاء الاصطناعي والمكونات الطبيعية 100% لنقدم لك تجربة غذائية لا تُنسى.',
        heroImage: 'https://i.ibb.co/6J8BHK9s/28.jpg',
        missionTitle: 'مهمتنا',
        missionText: 'توفير وجبات صحية فاخرة مصنوعة من مكونات طبيعية 100%. نحن نجعل الحياة الصحية بسيطة، لذيذة، ومتاحة للجميع.',
        featuresList: [
            'مكونات طبيعية 100%',
            'استشارات مدعومة بالذكاء الاصطناعي',
            'نظام اشتراك مرن',
            'توصيل دقيق في الموعد'
        ],
        contactPhone: '',
        appBannerTitle1: 'صحتك صارت',
        appBannerHighlight: 'أسهل وأقرب',
        appBannerText: 'حمل التطبيق الآن واستمتع بتجربة طلب أسرع، تتبع لخطتك الغذائية، وعروض حصرية. وجباتك الصحية بلمسة زر.',
        appBannerImage: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
        privacyPolicy: 'نحن نلتزم بحماية خصوصيتك...',
        returnPolicy: 'نظراً لطبيعة المنتجات الغذائية...',
        paymentPolicy: 'نقبل الدفع نقداً عند الاستلام...',
        socialFacebook: 'https://facebook.com',
        socialInstagram: 'https://instagram.com',
        socialTwitter: 'https://twitter.com',
        linkAndroid: '',
        linkIOS: ''
    };

    try {
      const docRef = doc(db, "content", "main_content");
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data() as SiteContent;
        return { 
            ...defaults, 
            ...data, 
            featuresList: data.featuresList || defaults.featuresList,
            contactPhone: data.contactPhone || defaults.contactPhone
        };
      } else {
        try { await setDoc(docRef, defaults); } catch(err) {}
        return defaults;
      }
    } catch (e) {
      console.warn("Firebase content unavailable, using defaults.");
      return defaults;
    }
  },

  saveContent: async (content: SiteContent): Promise<boolean> => {
    try {
      await setDoc(doc(db, "content", "main_content"), content);
      return true;
    } catch (e) {
      console.warn("Failed to save content", e);
      return false;
    }
  },

  // Meals
  getMeals: async (): Promise<Meal[]> => {
    try {
      const querySnapshot = await getDocs(collection(db, "meals"));
      const meals: Meal[] = [];
      querySnapshot.forEach((doc) => {
        meals.push(doc.data() as Meal);
      });

      if (meals.length === 0) {
        try {
            for (const m of MEALS) {
                await setDoc(doc(db, "meals", m.id), m);
            }
        } catch(err) {}
        return MEALS;
      }
      return meals;
    } catch (e) {
      return MEALS;
    }
  },
  addMeal: async (meal: Meal) => {
    await setDoc(doc(db, "meals", meal.id), meal);
  },
  deleteMeal: async (id: string) => {
    await deleteDoc(doc(db, "meals", id));
  },

  // Analytics Functions
  getAnalytics: async (): Promise<AnalyticsData> => {
      const defaultAnalytics: AnalyticsData = {
          totalVisits: 0,
          androidClicks: 0,
          iosClicks: 0,
          mealViews: {},
          visitHours: {}
      };

      try {
          const docRef = doc(db, "analytics", "main_stats");
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) {
              const data = docSnap.data();
              return {
                  ...defaultAnalytics,
                  ...data,
                  // Ensure objects exist if they are missing in DB
                  mealViews: data.mealViews || {},
                  visitHours: data.visitHours || {}
              } as AnalyticsData;
          } else {
              // Initialize if not exists
              await setDoc(docRef, defaultAnalytics);
              return defaultAnalytics;
          }
      } catch (e) {
          console.error("Error fetching analytics", e);
          return defaultAnalytics;
      }
  },

  logVisit: async () => {
      // Use setDoc with merge to safely update counters
      try {
          const docRef = doc(db, "analytics", "main_stats");
          const currentHour = new Date().getHours();
          await setDoc(docRef, {
              totalVisits: increment(1),
              visitHours: {
                  [currentHour]: increment(1)
              }
          }, { merge: true });
      } catch(e) { console.error("Track visit failed", e) }
  },

  logMealView: async (mealId: string) => {
      try {
          const docRef = doc(db, "analytics", "main_stats");
          await setDoc(docRef, {
              mealViews: {
                  [mealId]: increment(1)
              }
          }, { merge: true });
      } catch(e) { console.error("Track meal view failed", e) }
  },

  logAppClick: async (platform: 'android' | 'ios') => {
      try {
          const docRef = doc(db, "analytics", "main_stats");
          await setDoc(docRef, {
              [platform === 'android' ? 'androidClicks' : 'iosClicks']: increment(1)
          }, { merge: true });
      } catch(e) { console.error("Track app click failed", e) }
  },

  // Subscription Plans
  getSubscriptionPlans: async (): Promise<SubscriptionPlan[]> => {
    let plans: SubscriptionPlan[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "plans"));
      querySnapshot.forEach((doc) => {
        plans.push(doc.data() as SubscriptionPlan);
      });
    } catch (e) {}

    localPlans.forEach(lp => {
        const idx = plans.findIndex(p => p.id === lp.id);
        if (idx >= 0) plans[idx] = lp;
        else plans.push(lp);
    });

    if (plans.length === 0) {
         return [];
    }
    return plans;
  },

  saveSubscriptionPlan: async (plan: SubscriptionPlan) => {
    const existingIndex = localPlans.findIndex(p => p.id === plan.id);
    if (existingIndex >= 0) localPlans[existingIndex] = plan;
    else localPlans.push(plan);
    try { await setDoc(doc(db, "plans", plan.id), plan); } catch (e) {}
  },

  deleteSubscriptionPlan: async (id: string) => {
    localPlans = localPlans.filter(p => p.id !== id);
    try { await deleteDoc(doc(db, "plans", id)); } catch (e) {}
  },

  // Promo Codes
  getPromoCodes: async (): Promise<PromoCode[]> => {
    let promos: PromoCode[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "promos"));
      querySnapshot.forEach((doc) => {
        promos.push(doc.data() as PromoCode);
      });
    } catch (e) {}
    localPromos.forEach(lp => {
         const idx = promos.findIndex(p => p.id === lp.id);
         if (idx >= 0) promos[idx] = lp;
         else promos.push(lp);
    });
    return promos;
  },

  savePromoCode: async (promo: PromoCode) => {
    const idx = localPromos.findIndex(p => p.id === promo.id);
    if (idx >= 0) localPromos[idx] = promo;
    else localPromos.push(promo);
    try { await setDoc(doc(db, "promos", promo.id), promo); } catch (e) {}
  },

  deletePromoCode: async (id: string) => {
    localPromos = localPromos.filter(p => p.id !== id);
    try { await deleteDoc(doc(db, "promos", id)); } catch (e) {}
  },

  verifyPromoCode: async (code: string, type: 'MEALS' | 'SUBSCRIPTION'): Promise<PromoCode | null> => {
     const allPromos = await dataService.getPromoCodes();
     return allPromos.find(p => p.code === code && p.isActive && p.type === type) || null;
  }
};

