export const ChefDashboard: React.FC<ChefDashboardProps> = ({ onLogout }) => {
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'active' | 'out-for-delivery' | 'delivered'>('all');

  // States for Modals and Selection
  const [showAddModal, setShowAddModal] = useState(false);
  const [expandedSubId, setExpandedSubId] = useState<string | null>(null);

  const [newSub, setNewSub] = useState({
      customerName: '',
      phone: '',
      address: '',
      planId: '',
      deliverySlot: DeliverySlot.MORNING,
      notes: '',
      allergies: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [subsData, plansData] = await Promise.all([
        dataService.getSubscriptions(),
        dataService.getSubscriptionPlans()
    ]);
    setSubscriptions(subsData);
    setPlans(plansData);
    setLoading(false);
  };

  const handleUpdateStatus = async (id: string, updates: Partial<Subscription>) => {
      try {
          await dataService.updateSubscription(id, updates);
          setSubscriptions(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
      } catch (err) {
          alert('فشل في تحديث الحالة');
      }
  };

  const handleDeleteSub = async (id: string) => {
      if(confirm('هل أنت متأكد من حذف هذا الاشتراك نهائياً من النظام؟')) {
          // Note: Assuming a deleteSubscription method exists in dataService
          // If not, we can use a generic document delete logic
          try {
              await dataService.updateSubscription(id, { status: 'cancelled' as any }); // Or actual delete
              setSubscriptions(prev => prev.filter(s => s.id !== id));
              alert('تم حذف الاشتراك');
          } catch (err) {
              alert('حدث خطأ أثناء الحذف');
          }
      }
  };

  const handleAddSub = async (e: React.FormEvent) => {
      e.preventDefault();
      const selectedPlan = plans.find(p => p.id === newSub.planId);
      if (!selectedPlan) {
          alert('يرجى اختيار باقة');
          return;
      }

      const subscription: Subscription = {
          id: `sub_chef_${Date.now()}`,
          date: new Date().toISOString(),
          address: newSub.address,
          phone: newSub.phone,
          deliverySlot: newSub.deliverySlot,
          planTitle: selectedPlan.title,
          pricePaid: selectedPlan.price,
          duration: selectedPlan.durationLabel,
          status: 'active',
          notes: newSub.notes,
          deliveredCount: 0,
          postponedCount: 0,
          user: {
              id: newSub.phone,
              name: newSub.customerName,
              phone: newSub.phone,
              allergies: newSub.allergies,
              hasProfile: true,
              age: '', gender: '', height: '', weight: '', goal: ''
          }
      };

      try {
          await dataService.saveSubscription(subscription);
          setShowAddModal(false);
          setNewSub({ customerName: '', phone: '', address: '', planId: '', deliverySlot: DeliverySlot.MORNING, notes: '', allergies: '' });
          loadData();
          alert('تم إضافة الاشتراك بنجاح');
      } catch (err) {
          alert('حدث خطأ أثناء حفظ الاشتراك');
      }
  };

  const handlePostpone = async (sub: Subscription) => {
      if(confirm('هل أنت متأكد من تأجيل وجبة اليوم؟ ستضاف الوجبة إلى نهاية اشتراك الزبون.')) {
          const currentPostponed = sub.postponedCount || 0;
          await handleUpdateStatus(sub.id, {
              status: 'active',
              postponedCount: currentPostponed + 1,
              departureTime: '',
              arrivalTime: ''
          });
          alert('تم تأجيل الوجبة بنجاح');
      }
  };

  const renderMonthlySchedule = (sub: Subscription) => {
      const startDate = new Date(sub.date);
      const days = Array.from({ length: 30 }); // Monthly view: 30 days
      const customer = sub.user;

      return (
          <div className="mt-4 border-t pt-4 animate-fade-in">
              <h4 className="font-bold text-uh-dark mb-4 flex items-center gap-2">
                  <CalendarDays size={18} className="text-uh-green" />
                  الجدول الشهري (30 يوماً من تاريخ البدء)
              </h4>
              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 lg:grid-cols-6 gap-2">
                  {days.map((_, idx) => {
                      const currentDate = new Date(startDate);
                      currentDate.setDate(startDate.getDate() + idx);
                      const isPast = currentDate < new Date(new Date().setHours(0,0,0,0));
                      const isToday = currentDate.toDateString() === new Date().toDateString();

                      // Map to 7-day cycle if plan exists
                      const dayPlanIndex = idx % 7;
                      const dayPlan = customer?.savedPlan?.[dayPlanIndex];

                      return (
                          <div key={idx} className={`p-2 rounded-lg text-center border transition ${
                              isToday ? 'bg-uh-gold/20 border-uh-gold' : 
                              isPast ? 'bg-gray-50 border-gray-100 grayscale' : 'bg-white border-gray-100'
                          }`}>
                              <div className="text-[10px] text-gray-400 font-mono">
                                  {currentDate.toLocaleDateString('ar-EG', { day: 'numeric', month: 'short' })}
                              </div>
                              <div className="text-xs font-bold mt-1">يوم {idx + 1}</div>
                              {dayPlan && (
                                  <div className="mt-1 text-[9px] text-uh-greenDark truncate" title={dayPlan.lunch.name}>
                                      {dayPlan.lunch.name}
                                  </div>
                              )}
                              {isToday && <div className="text-[8px] bg-uh-green text-white rounded mt-1 px-1">اليوم</div>}
                          </div>
                      );
                  })}
              </div>
          </div>
      );
  };

  const filteredSubs = subscriptions.filter(s => {
      if (filter === 'all') return true;
      return s.status === filter;
  });

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-arabic" dir="rtl">
      {/* Header */}
      <header className="bg-uh-dark text-white p-4 shadow-lg flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
              <div className="bg-uh-green p-2 rounded-lg">
                <ChefHat size={24} />
              </div>
              <h1 className="text-xl font-bold">لوحة تحكم الشيف</h1>
          </div>
          <div className="flex items-center gap-4">
              <button 
                onClick={() => setShowAddModal(true)}
                className="bg-uh-gold text-uh-dark px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-yellow-500 transition shadow-sm"
              >
                  <Plus size={20}/> <span>اشتراك جديد</span>
              </button>
              <button onClick={onLogout} className="flex items-center gap-2 text-red-400 hover:text-red-300 font-bold transition">
                  <LogOut size={20}/> <span>خروج</span>
              </button>
          </div>
      </header>

      <main className="flex-1 container mx-auto p-4 md:p-8 space-y-8">

          {/* Stats Bar */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div onClick={() => setFilter('all')} className={`p-4 rounded-xl shadow-sm cursor-pointer transition ${filter === 'all' ? 'bg-uh-gold text-uh-dark' : 'bg-white'}`}>
                  <p className="text-xs opacity-70 uppercase font-bold">إجمالي الاشتراكات</p>
                  <p className="text-2xl font-bold">{subscriptions.length}</p>
              </div>
              <div onClick={() => setFilter('out-for-delivery')} className={`p-4 rounded-xl shadow-sm cursor-pointer transition ${filter === 'out-for-delivery' ? 'bg-blue-500 text-white' : 'bg-white'}`}>
                  <p className="text-xs opacity-70 uppercase font-bold">خرجت للتوصيل</p>
                  <p className="text-2xl font-bold">{subscriptions.filter(s => s.status === 'out-for-delivery').length}</p>
              </div>
              <div onClick={() => setFilter('delivered')} className={`p-4 rounded-xl shadow-sm cursor-pointer transition ${filter === 'delivered' ? 'bg-uh-green text-white' : 'bg-white'}`}>
                  <p className="text-xs opacity-70 uppercase font-bold">تم التسليم</p>
                  <p className="text-2xl font-bold">{subscriptions.filter(s => s.status === 'delivered').length}</p>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm">
                  <p className="text-xs text-gray-400 uppercase font-bold">المؤجلات</p>
                  <p className="text-2xl font-bold text-red-500">{subscriptions.reduce((sum, s) => sum + (s.postponedCount || 0), 0)}</p>
              </div>
          </div>

          <div className="flex justify-between items-center">
              <h2 className="text-2xl font-bold text-uh-dark">جدول تسليم وجبات اليوم</h2>
              <button onClick={loadData} className="bg-white p-2 rounded-full shadow hover:bg-gray-100 transition"><RefreshCcw size={18}/></button>
          </div>

          {loading ? (
              <div className="text-center py-20 text-gray-400">جاري تحميل البيانات...</div>
          ) : (
              <div className="grid gap-6">
                  {filteredSubs.map(sub => {
                      const customer = sub.user;
                      const isExpanded = expandedSubId === sub.id;
                      const today = new Date().getDay(); 
                      const currentPlanDay = customer?.savedPlan?.[today] || customer?.savedPlan?.[0];

                      return (
                          <div key={sub.id} className={`bg-white rounded-2xl shadow-sm border overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-uh-green border-transparent' : 'border-gray-100 hover:border-uh-green/50'}`}>
                              <div className="grid md:grid-cols-3">

                                  {/* Section 1: Customer Info */}
                                  <div className="p-6 border-l border-gray-100 relative group">
                                      <button 
                                        onClick={() => handleDeleteSub(sub.id)}
                                        className="absolute top-2 left-2 p-1.5 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-full transition opacity-0 group-hover:opacity-100"
                                        title="حذف الاشتراك"
                                      >
                                          <Trash2 size={16} />
                                      </button>

                                      <div className="flex items-center gap-3 mb-4 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                          <div className="w-12 h-12 bg-uh-cream rounded-full flex items-center justify-center text-uh-dark font-bold">
                                              <User size={24}/>
                                          </div>
                                          <div>
                                              <h3 className="font-bold text-lg text-uh-dark">{customer?.name || 'زبون غير مسجل'}</h3>
                                              <p className="text-xs bg-uh-gold/20 text-uh-greenDark px-2 py-0.5 rounded-full inline-block font-bold">
                                                  {sub.planTitle}
                                              </p>
                                          </div>
                                      </div>

                                      <div className="space-y-2 text-sm">
                                          <a href={`tel:${sub.phone}`} className="flex items-center gap-2 text-blue-600 hover:underline">
                                              <Phone size={14}/> {sub.phone}
                                          </a>
                                          <div className="flex items-start gap-2 text-gray-500">
                                              <MapPin size={14} className="mt-1 flex-shrink-0"/>
                                              <span>{sub.address}</span>
                                          </div>
                                          <div className="flex items-center gap-2 text-uh-greenDark font-bold">
                                              <Clock size={14}/> {sub.deliverySlot}
                                          </div>
                                      </div>
                                  </div>

                                  {/* Section 2: Meal & Notes */}
                                  <div className="p-6 border-l border-gray-100 bg-gray-50/50 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                      <div className="flex justify-between items-start mb-3">
                                          <h4 className="text-xs font-bold text-gray-400 uppercase">وجبات اليوم والملاحظات</h4>
                                          {isExpanded ? <ChevronUp size={16} className="text-gray-400"/> : <ChevronDown size={16} className="text-gray-400"/>}
                                      </div>
                                      {currentPlanDay ? (
                                          <div className="space-y-3">
                                              <div className="flex gap-2 items-center bg-white p-2 rounded-lg shadow-sm">
                                                  <div className="w-10 h-10 rounded overflow-hidden">
                                                      <OptimizedImage src={currentPlanDay.lunch.image} alt="" width={50}/>
                                                  </div>
                                                  <div className="text-xs">
                                                      <p className="font-bold text-uh-dark">الغداء: {currentPlanDay.lunch.name}</p>
                                                      <p className="text-gray-400">العشاء: {currentPlanDay.dinner.name}</p>
                                                  </div>
                                              </div>
                                          </div>
                                      ) : <p className="text-sm text-red-400">لا يوجد جدول محدد اليوم</p>}

                                      <div className="mt-4 p-3 rounded-lg bg-red-50 border border-red-100">
                                          <div className="flex items-center gap-2 text-red-600 mb-1">
                                              <AlertTriangle size={14}/>
                                              <span className="text-xs font-bold uppercase">حساسية / استبدال:</span>
                                          </div>
                                          <p className="text-sm text-red-700 font-bold">{customer?.allergies || 'لا يوجد'}</p>
                                      </div>
                                  </div>

                                  {/* Section 3: Delivery Actions */}
                                  <div className="p-6 flex flex-col justify-between">
                                      <div className="space-y-4">
                                          <div className="flex justify-between items-center text-sm">
                                              <span className="text-gray-400">الحالة:</span>
                                              <span className={`font-bold px-2 py-1 rounded-lg text-xs ${
                                                  sub.status === 'delivered' ? 'bg-green-100 text-green-700' :
                                                  sub.status === 'out-for-delivery' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-600'
                                              }`}>
                                                  {sub.status === 'delivered' ? 'تم التسليم' :
                                                   sub.status === 'out-for-delivery' ? 'في الطريق' : 'بانتظار التجهيز'}
                                              </span>
                                          </div>

                                          <div className="space-y-2">
                                              <div className="flex justify-between text-xs">
                                                  <span>خروج: {sub.departureTime || '--:--'}</span>
                                                  <span>وصول: {sub.arrivalTime || '--:--'}</span>
                                              </div>
                                          </div>
                                      </div>

                                      <div className="grid grid-cols-2 gap-2 mt-4">
                                          {sub.status !== 'delivered' && (
                                              <>
                                                {sub.status === 'active' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(sub.id, { status: 'out-for-delivery', departureTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}) })}
                                                        className="col-span-2 bg-uh-dark text-white py-2 rounded-lg font-bold hover:bg-black transition flex items-center justify-center gap-2"
                                                    >
                                                        <Truck size={16}/> خروج الطلب
                                                    </button>
                                                )}
                                                {sub.status === 'out-for-delivery' && (
                                                    <button 
                                                        onClick={() => handleUpdateStatus(sub.id, { status: 'delivered', arrivalTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}), deliveredCount: (sub.deliveredCount || 0) + 1 })}
                                                        className="col-span-2 bg-uh-green text-white py-2 rounded-lg font-bold hover:bg-uh-greenDark transition flex items-center justify-center gap-2"
                                                    >
                                                        <CheckCircle size={16}/> تم التسليم
                                                    </button>
                                                )}
                                                <button 
                                                    onClick={() => handlePostpone(sub)}
                                                    className="col-span-2 border border-red-200 text-red-500 py-2 rounded-lg font-bold hover:bg-red-50 transition text-xs"
                                                >
                                                    تأجيل وجبة اليوم
                                                </button>
                                              </>
                                          )}
                                          {sub.status === 'delivered' && (
                                              <div className="col-span-2 bg-green-50 text-green-700 py-2 rounded-lg text-center font-bold text-sm">
                                                  مكتمل اليوم ✅
                                              </div>
                                          )}
                                      </div>
                                  </div>
                              </div>

                              {/* Expanded Monthly Schedule */}
                              {isExpanded && (
                                  <div className="bg-gray-50/30 p-6 border-t border-gray-100">
                                      {renderMonthlySchedule(sub)}
                                  </div>
                              )}
                          </div>
                      );
                  })}
                  {filteredSubs.length === 0 && (
                      <div className="bg-white p-10 rounded-2xl border border-dashed border-gray-300 text-center text-gray-400">
                          لا توجد اشتراكات
                      </div>
                  )}
              </div>
          )}
      </main>

      {/* Add Subscription Modal */}
      {showAddModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-xl p-8 shadow-2xl my-8">
                  <div className="flex justify-between items-center mb-6 border-b pb-4">
                      <div className="flex items-center gap-2">
                          <Plus className="text-uh-green" />
                          <h3 className="text-xl font-bold">إضافة اشتراك يدوي</h3>
                      </div>
                      <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-red-500"><X /></button>
                  </div>

                  <form onSubmit={handleAddSub} className="space-y-4">
                      <div className="grid md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-bold mb-1">اسم الزبون</label>
                              <input required className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.customerName} onChange={e => setNewSub({...newSub, customerName: e.target.value})} />
                          </div>
                          <div>
                              <label className="block text-sm font-bold mb-1">رقم الهاتف</label>
                              <input required type="tel" className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.phone} onChange={e => setNewSub({...newSub, phone: e.target.value})} />
                          </div>
                      </div>

                      <div>
                          <label className="block text-sm font-bold mb-1">العنوان بالتفصيل</label>
                          <textarea required className="w-full border p-3 rounded-xl bg-gray-50" rows={2} value={newSub.address} onChange={e => setNewSub({...newSub, address: e.target.value})} />
                      </div>

                      <div className="grid md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-bold mb-1">الباقة</label>
                              <select required className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.planId} onChange={e => setNewSub({...newSub, planId: e.target.value})}>
                                  <option value="">اختر الباقة...</option>
                                  {plans.map(p => <option key={p.id} value={p.id}>{p.title} ({p.price} د.أ)</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="block text-sm font-bold mb-1">وقت التوصيل</label>
                              <select className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.deliverySlot} onChange={e => setNewSub({...newSub, deliverySlot: e.target.value as DeliverySlot})}>
                                  <option value={DeliverySlot.MORNING}>صباحي (10-12)</option>
                                  <option value={DeliverySlot.EVENING}>مسائي (3-5)</option>
                              </select>
                          </div>
                      </div>

                      <div className="grid md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-sm font-bold mb-1 text-red-500">حساسية / استبدال</label>
                              <input className="w-full border border-red-100 p-3 rounded-xl bg-red-50" value={newSub.allergies} onChange={e => setNewSub({...newSub, allergies: e.target.value})} placeholder="مثال: بدون بصل" />
                          </div>
                          <div>
                              <label className="block text-sm font-bold mb-1">ملاحظات إضافية</label>
                              <input className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.notes} onChange={e => setNewSub({...newSub, notes: e.target.value})} />
                          </div>
                      </div>

                      <button type="submit" className="w-full bg-uh-green text-white font-bold py-4 rounded-xl hover:bg-uh-greenDark transition shadow-lg mt-4">
                          حفظ وتفعيل الاشتراك
                      </button>
                  </form>
              </div>
          </div>
      )}

      <footer className="bg-white border-t border-gray-200 p-4 text-center text-xs text-gray-400">
          تم التصميم بحب لـ Uncle Healthy © 2025
      </footer>
    </div>
  );
};

export interface Meal {
  id: string;
  name: string;
  description: string;
  image: string;
  price: number;
  macros: {
    protein: number;
    carbs: number;
    fats: number;
    calories: number;
  };
  ingredients: string[];
  instructions: string[];
}

export interface DayConfig {
  mealId: string;
  count: number;
  status: 'pending' | 'delivered' | 'postponed';
}

export interface UserProfile {
  id: string;
  password?: string;
  name: string;
  age: string;
  gender: string;
  height: string;
  weight: string;
  goal: string;
  allergies: string;
  phone: string;
  hasProfile: boolean;
  savedPlan?: DailyPlan[];
  isAdmin?: boolean;
  isChef?: boolean;
}

export enum SubscriptionDuration {
  WEEKLY = 'Weekly',
  MONTHLY = 'Monthly'
}

export enum DeliverySlot {
  MORNING = '10:00 - 12:00',
  EVENING = '15:00 - 17:00'
}

export interface SubscriptionPlan {
  id: string;
  title: string;
  price: number;
  image?: string;
  features: string[];
  durationLabel: string;
  isPopular?: boolean;
}

export interface PromoCode {
  id: string;
  code: string;
  type: 'MEALS' | 'SUBSCRIPTION';
  discountAmount: number;
  isPercentage: boolean;
  isActive: boolean;
}

export interface Subscription {
  id: string;
  duration: string;
  deliverySlot: DeliverySlot;
  address: string;
  phone: string;
  notes?: string; 
  user?: UserProfile;
  date: string;
  planTitle?: string;
  pricePaid?: number;
  // Enhanced tracking
  totalMeals: number;
  deliveredCount: number;
  postponedCount: number;
  dailyConfigs?: Record<string, DayConfig>; // Key is date string YYYY-MM-DD
  departureTime?: string;
  arrivalTime?: string;
  status: 'active' | 'postponed' | 'delivered' | 'out-for-delivery' | 'cancelled';
}

export interface DailyPlan {
  day: string;
  breakfast: Meal;
  lunch: Meal;
  dinner: Meal;
}

export interface CartItem extends Meal {
  quantity: number;
}

export interface Order {
  id: string;
  user: UserProfile;
  items: CartItem[];
  total: number;
  address: string;
  phone: string;
  date: string;
  status: 'pending' | 'completed' | 'cancelled';
  promoCode?: string;
  discountApplied?: number;
  tax?: number;
}

export interface SiteContent {
  heroTitle: string;
  heroSubtitle: string;
  heroImage: string;
  missionTitle: string;
  missionText: string;
  featuresList: string[];
  contactPhone: string;
  appBannerTitle1?: string;
  appBannerHighlight?: string;
  appBannerText?: string;
  appBannerImage?: string;
  privacyPolicy: string;
  returnPolicy: string;
  paymentPolicy: string;
  socialFacebook: string;
  socialInstagram: string;
  socialTwitter: string;
  linkAndroid: string;
  linkIOS: string;
}

export interface AnalyticsData {
  totalVisits: number;
  androidClicks: number;
  iosClicks: number;
  mealViews: Record<string, number>;
  visitHours: Record<string, number>;
}

export type PageView = 'HOME' | 'LOGIN' | 'ONBOARDING' | 'STORE' | 'PROFILE' | 'SUBSCRIPTION' | 'MEAL_DETAIL' | 'CART' | 'ADMIN' | 'CHEF' | 'PRIVACY_POLICY' | 'RETURN_POLICY' | 'PAYMENT_POLICY';

import React, { useState, useEffect } from 'react';
import { Subscription, UserProfile, SubscriptionPlan, DeliverySlot, Meal, DayConfig } from '../types';
import { dataService } from '../services/dataService';
import { ChefHat, LogOut, Clock, MapPin, Phone, Truck, CheckCircle, AlertTriangle, Calendar, User, Info, RefreshCcw, Plus, Trash2, X, ChevronDown, ChevronUp, CalendarDays, Edit3, Hash } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface ChefDashboardProps {
  onLogout: () => void;
}

export const ChefDashboard: React.FC<ChefDashboardProps> = ({ onLogout }) => {
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [meals, setMeals] = useState<Meal[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'active' | 'out-for-delivery' | 'delivered'>('all');

  // Modals States
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDayModal, setShowDayModal] = useState(false);
  const [expandedSubId, setExpandedSubId] = useState<string | null>(null);

  // Day Editing State
  const [activeDayEdit, setActiveDayEdit] = useState<{subId: string, date: string} | null>(null);
  const [dayEditForm, setDayEditForm] = useState<DayConfig>({ mealId: '', count: 1, status: 'pending' });

  const [newSub, setNewSub] = useState({
      customerName: '',
      phone: '',
      address: '',
      planId: '',
      totalMeals: 30,
      deliverySlot: DeliverySlot.MORNING,
      notes: '',
      allergies: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [subsData, plansData, mealsData] = await Promise.all([
        dataService.getSubscriptions(),
        dataService.getSubscriptionPlans(),
        dataService.getMeals()
    ]);
    setSubscriptions(subsData);
    setPlans(plansData);
    setMeals(mealsData);
    setLoading(false);
  };

  const handleUpdateStatus = async (id: string, updates: Partial<Subscription>) => {
      try {
          await dataService.updateSubscription(id, updates);
          setSubscriptions(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
      } catch (err) {
          alert('فشل في تحديث الحالة');
      }
  };

  const handleAddSub = async (e: React.FormEvent) => {
      e.preventDefault();
      const selectedPlan = plans.find(p => p.id === newSub.planId);
      if (!selectedPlan) { alert('يرجى اختيار باقة'); return; }

      const subscription: Subscription = {
          id: `sub_chef_${Date.now()}`,
          date: new Date().toISOString().split('T')[0],
          address: newSub.address,
          phone: newSub.phone,
          deliverySlot: newSub.deliverySlot,
          planTitle: selectedPlan.title,
          pricePaid: selectedPlan.price,
          duration: selectedPlan.durationLabel,
          status: 'active',
          totalMeals: Number(newSub.totalMeals),
          deliveredCount: 0,
          postponedCount: 0,
          notes: newSub.notes,
          dailyConfigs: {},
          user: {
              id: newSub.phone,
              name: newSub.customerName,
              phone: newSub.phone,
              allergies: newSub.allergies,
              hasProfile: true,
              age: '', gender: '', height: '', weight: '', goal: ''
          }
      };

      await dataService.saveSubscription(subscription);
      setShowAddModal(false);
      setNewSub({ customerName: '', phone: '', address: '', planId: '', totalMeals: 30, deliverySlot: DeliverySlot.MORNING, notes: '', allergies: '' });
      loadData();
  };

  const handleDayClick = (sub: Subscription, date: string) => {
      const existing = sub.dailyConfigs?.[date] || { mealId: '', count: 1, status: 'pending' };
      setActiveDayEdit({ subId: sub.id, date });
      setDayEditForm(existing);
      setShowDayModal(true);
  };

  const saveDayConfig = async () => {
      if (!activeDayEdit) return;
      const sub = subscriptions.find(s => s.id === activeDayEdit.subId);
      if (!sub) return;

      const newConfigs = { ...sub.dailyConfigs, [activeDayEdit.date]: dayEditForm };
      await handleUpdateStatus(sub.id, { dailyConfigs: newConfigs });
      setShowDayModal(false);
  };

  const handlePostpone = async (sub: Subscription) => {
      if(confirm('سيتم تأجيل وجبة اليوم وإضافة يوم إضافي للاشتراك. متابعة؟')) {
          const newPostponedCount = (sub.postponedCount || 0) + 1;
          const todayKey = new Date().toISOString().split('T')[0];

          const newConfigs = { ...sub.dailyConfigs };
          if (newConfigs[todayKey]) {
              newConfigs[todayKey].status = 'postponed';
          } else {
              newConfigs[todayKey] = { mealId: '', count: 0, status: 'postponed' };
          }

          await handleUpdateStatus(sub.id, {
              status: 'active',
              postponedCount: newPostponedCount,
              dailyConfigs: newConfigs,
              departureTime: '',
              arrivalTime: ''
          });
          alert('تم التأجيل وتمديد المدة');
      }
  };

  const renderMonthlySchedule = (sub: Subscription) => {
      const startDate = new Date(sub.date);
      // Monthly view is 30 days + postponed days extension
      const totalDaysToShow = 30 + (sub.postponedCount || 0);
      const days = Array.from({ length: totalDaysToShow });

      return (
          <div className="mt-4 border-t pt-4 animate-fade-in">
              <div className="flex justify-between items-center mb-4">
                  <h4 className="font-bold text-uh-dark flex items-center gap-2">
                      <CalendarDays size={18} className="text-uh-green" />
                      الجدول الزمني (ممتد لـ {totalDaysToShow} يوم)
                  </h4>
                  <p className="text-xs text-gray-400">اضغط على اليوم لتحديد الوجبات والعدد</p>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-2">
                  {days.map((_, idx) => {
                      const currentDate = new Date(startDate);
                      currentDate.setDate(startDate.getDate() + idx);
                      const dateKey = currentDate.toISOString().split('T')[0];
                      const config = sub.dailyConfigs?.[dateKey];
                      const isToday = currentDate.toDateString() === new Date().toDateString();
                      const isPast = currentDate < new Date(new Date().setHours(0,0,0,0));
                      const meal = meals.find(m => m.id === config?.mealId);

                      return (
                          <div 
                            key={idx} 
                            onClick={() => handleDayClick(sub, dateKey)}
                            className={`p-2 rounded-xl text-center border cursor-pointer transition-all hover:scale-105 ${
                                isToday ? 'bg-uh-gold/10 border-uh-gold' : 
                                config?.status === 'postponed' ? 'bg-red-50 border-red-200' :
                                isPast ? 'bg-gray-50 border-gray-100' : 'bg-white border-gray-100'
                            }`}
                          >
                              <div className="text-[10px] text-gray-400 mb-1">
                                  {currentDate.toLocaleDateString('ar-EG', { day: 'numeric', month: 'short' })}
                              </div>
                              <div className="text-xs font-bold">يوم {idx + 1}</div>

                              {config && config.count > 0 && (
                                  <div className="mt-1">
                                      <div className="text-[10px] bg-uh-green/10 text-uh-greenDark rounded-full px-1 truncate font-bold">
                                          {meal ? meal.name : 'وجبة مخصصة'}
                                      </div>
                                      <div className="text-[10px] font-bold text-uh-dark">العدد: {config.count}</div>
                                  </div>
                              )}

                              {config?.status === 'postponed' && (
                                  <div className="text-[8px] text-red-500 font-bold mt-1">مؤجل ⏳</div>
                              )}
                              {isToday && <div className="text-[8px] bg-uh-green text-white rounded mt-1 px-1">اليوم</div>}
                          </div>
                      );
                  })}
              </div>
          </div>
      );
  };

  const filteredSubs = subscriptions.filter(s => filter === 'all' || s.status === filter);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-arabic" dir="rtl">
      {/* Header */}
      <header className="bg-uh-dark text-white p-4 shadow-lg flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
              <div className="bg-uh-green p-2 rounded-lg"><ChefHat size={24} /></div>
              <h1 className="text-xl font-bold">إدارة مطبخ Uncle Healthy</h1>
          </div>
          <div className="flex items-center gap-4">
              <button onClick={() => setShowAddModal(true)} className="bg-uh-gold text-uh-dark px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-yellow-500 transition"><Plus size={20}/> <span>إضافة اشتراك</span></button>
              <button onClick={onLogout} className="text-red-400 hover:text-red-300 transition"><LogOut size={20}/></button>
          </div>
      </header>

      <main className="flex-1 container mx-auto p-4 md:p-8 space-y-6">

          {/* Dashboard Stats Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات الموزعة</p>
                  <p className="text-2xl font-bold text-uh-green">{subscriptions.reduce((sum, s) => sum + (s.deliveredCount || 0), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات المتبقية</p>
                  <p className="text-2xl font-bold text-uh-dark">{subscriptions.reduce((sum, s) => sum + (s.totalMeals - (s.deliveredCount || 0)), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الطلبات النشطة</p>
                  <p className="text-2xl font-bold text-blue-500">{subscriptions.filter(s => s.status !== 'delivered').length}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">أيام التأجيل</p>
                  <p className="text-2xl font-bold text-red-500">{subscriptions.reduce((sum, s) => sum + (s.postponedCount || 0), 0)}</p>
              </div>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
              {['all', 'active', 'out-for-delivery', 'delivered'].map((f) => (
                  <button key={f} onClick={() => setFilter(f as any)} className={`px-4 py-2 rounded-full text-xs font-bold transition whitespace-nowrap ${filter === f ? 'bg-uh-dark text-white' : 'bg-white text-gray-500 border hover:bg-gray-50'}`}>
                      {f === 'all' ? 'الكل' : f === 'active' ? 'بانتظار التجهيز' : f === 'out-for-delivery' ? 'في الطريق' : 'تم التسليم'}
                  </button>
              ))}
          </div>

          <div className="grid gap-6">
              {filteredSubs.map(sub => {
                  const customer = sub.user;
                  const isExpanded = expandedSubId === sub.id;
                  const todayKey = new Date().toISOString().split('T')[0];
                  const todayConfig = sub.dailyConfigs?.[todayKey];
                  const todayMeal = meals.find(m => m.id === todayConfig?.mealId);
                  const remaining = sub.totalMeals - (sub.deliveredCount || 0);

                  return (
                      <div key={sub.id} className={`bg-white rounded-3xl shadow-sm border overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-uh-green' : 'border-gray-100'}`}>
                          <div className="grid md:grid-cols-3">

                              <div className="p-6 border-l border-gray-50">
                                  <div className="flex items-center gap-3 mb-4">
                                      <div className="w-12 h-12 bg-uh-cream rounded-full flex items-center justify-center text-uh-dark"><User size={24}/></div>
                                      <div>
                                          <h3 className="font-bold text-lg text-uh-dark">{customer?.name}</h3>
                                          <div className="flex gap-2 items-center">
                                              <span className="text-[10px] bg-uh-gold/20 text-uh-greenDark px-2 py-0.5 rounded-full font-bold">{sub.planTitle}</span>
                                              <span className="text-[10px] bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full font-bold">بدأ في: {sub.date}</span>
                                          </div>
                                      </div>
                                  </div>
                                  <div className="space-y-2 text-sm">
                                      <a href={`tel:${sub.phone}`} className="flex items-center gap-2 text-blue-600 font-bold"><Phone size={14}/> {sub.phone}</a>
                                      <p className="text-gray-500 flex items-start gap-2"><MapPin size={14} className="mt-1 flex-shrink-0"/> {sub.address}</p>
                                  </div>
                              </div>

                              <div className="p-6 bg-gray-50/50 border-l border-gray-50 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                  <div className="flex justify-between items-start mb-4">
                                      <h4 className="text-xs font-bold text-gray-400 uppercase">مهمة المطبخ لليوم</h4>
                                      <div className="flex gap-1">
                                          <span className="text-[10px] bg-white border border-gray-200 px-2 py-0.5 rounded-full font-bold">المتبقي: {remaining}</span>
                                          {isExpanded ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                      </div>
                                  </div>

                                  {todayConfig && todayConfig.count > 0 ? (
                                      <div className="bg-white p-3 rounded-2xl shadow-sm border border-uh-green/20">
                                          <div className="flex items-center gap-3">
                                              {todayMeal && <img src={todayMeal.image} className="w-10 h-10 rounded-lg object-cover" alt=""/>}
                                              <div>
                                                  <p className="font-bold text-sm">{todayMeal ? todayMeal.name : 'وجبة مخصصة'}</p>
                                                  <p className="text-uh-green font-bold text-xs">العدد: {todayConfig.count}</p>
                                              </div>
                                          </div>
                                      </div>
                                  ) : (
                                      <div className="text-center py-4 text-gray-400 text-xs italic">لا توجد وجبات مبرمجة لليوم - اضغط للبرمجة</div>
                                  )}

                                  <div className="mt-3 p-2 rounded-xl bg-red-50 text-red-700 text-xs font-bold">
                                      ⚠️ {customer?.allergies || 'لا توجد ملاحظات صحية'}
                                  </div>
                              </div>

                              <div className="p-6 flex flex-col justify-between">
                                  <div className="flex justify-between items-center mb-4">
                                      <span className="text-[10px] text-gray-400 font-bold">الحالة: {sub.status}</span>
                                      <div className="flex items-center gap-1 text-uh-greenDark font-bold text-xs"><Clock size={12}/> {sub.deliverySlot}</div>
                                  </div>

                                  <div className="grid grid-cols-2 gap-2">
                                      {sub.status !== 'delivered' ? (
                                          <>
                                              {sub.status === 'active' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'out-for-delivery', departureTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}) })} className="col-span-2 bg-uh-dark text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2"><Truck size={16}/> خروج الطلب</button>
                                              )}
                                              {sub.status === 'out-for-delivery' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'delivered', arrivalTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}), deliveredCount: (sub.deliveredCount || 0) + (todayConfig?.count || 1) })} className="col-span-2 bg-uh-green text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2"><CheckCircle size={16}/> تم التسليم</button>
                                              )}
                                              <button onClick={() => handlePostpone(sub)} className="col-span-2 border border-red-200 text-red-500 py-2 rounded-xl text-xs font-bold hover:bg-red-50 transition">تأجيل لليوم (تمديد الاشتراك)</button>
                                          </>
                                      ) : (
                                          <div className="col-span-2 bg-green-50 text-green-700 py-2 rounded-xl text-center font-bold text-xs">اكتمل التوصيل اليوم ✅</div>
                                      )}
                                  </div>
                              </div>
                          </div>

                          {isExpanded && <div className="p-6 bg-gray-50/20 border-t border-gray-100">{renderMonthlySchedule(sub)}</div>}
                      </div>
                  );
              })}
          </div>
      </main>

      {/* Day Editing Modal */}
      {showDayModal && activeDayEdit && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
              <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl">
                  <div className="flex justify-between items-center mb-6">
                      <div className="flex items-center gap-2 text-uh-dark">
                          <Edit3 className="text-uh-green" />
                          <h3 className="font-bold">برمجة يوم: {activeDayEdit.date}</h3>
                      </div>
                      <button onClick={() => setShowDayModal(false)}><X/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-sm font-bold mb-2">الوجبة من المتجر</label>
                          <select 
                            className="w-full border p-3 rounded-xl bg-gray-50 outline-none focus:ring-2 focus:ring-uh-green"
                            value={dayEditForm.mealId}
                            onChange={e => setDayEditForm({...dayEditForm, mealId: e.target.value})}
                          >
                              <option value="">اختر وجبة...</option>
                              {meals.map(m => <option key={m.id} value={m.id}>{m.name} - {m.macros.calories} Cal</option>)}
                          </select>
                      </div>

                      <div>
                          <label className="block text-sm font-bold mb-2 flex items-center gap-2"><Hash size={16}/> عدد الوجبات لهذا اليوم</label>
                          <div className="flex items-center gap-4 bg-gray-50 p-2 rounded-xl justify-center">
                              <button onClick={() => setDayEditForm({...dayEditForm, count: Math.max(0, dayEditForm.count - 1)})} className="bg-white p-2 rounded-lg shadow-sm"><X size={14}/></button>
                              <span className="text-xl font-bold w-10 text-center">{dayEditForm.count}</span>
                              <button onClick={() => setDayEditForm({...dayEditForm, count: dayEditForm.count + 1})} className="bg-white p-2 rounded-lg shadow-sm"><Plus size={14}/></button>
                          </div>
                      </div>

                      <button onClick={saveDayConfig} className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg hover:bg-uh-greenDark transition">حفظ إعدادات اليوم</button>
                  </div>
              </div>
          </div>
      )}

      {/* Add Subscription Modal */}
      {showAddModal && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-xl p-8 shadow-2xl my-8">
                  <div className="flex justify-between items-center mb-6 border-b pb-4">
                      <h3 className="text-xl font-bold flex items-center gap-2"><Plus className="text-uh-green" /> تفعيل اشتراك جديد</h3>
                      <button onClick={() => setShowAddModal(false)}><X /></button>
                  </div>

                  <form onSubmit={handleAddSub} className="space-y-4">
                      <div className="grid md:grid-cols-2 gap-4">
                          <input required placeholder="اسم الزبون" className="border p-3 rounded-xl bg-gray-50" value={newSub.customerName} onChange={e => setNewSub({...newSub, customerName: e.target.value})} />
                          <input required type="tel" placeholder="رقم الهاتف" className="border p-3 rounded-xl bg-gray-50" value={newSub.phone} onChange={e => setNewSub({...newSub, phone: e.target.value})} />
                      </div>
                      <textarea required placeholder="العنوان بالتفصيل" className="w-full border p-3 rounded-xl bg-gray-50" rows={2} value={newSub.address} onChange={e => setNewSub({...newSub, address: e.target.value})} />

                      <div className="grid md:grid-cols-3 gap-4">
                          <div className="md:col-span-2">
                              <label className="text-xs font-bold text-gray-400">الباقة</label>
                              <select required className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.planId} onChange={e => setNewSub({...newSub, planId: e.target.value})}>
                                  <option value="">اختر باقة...</option>
                                  {plans.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="text-xs font-bold text-gray-400">إجمالي الوجبات</label>
                              <input type="number" className="w-full border p-3 rounded-xl bg-gray-50" value={newSub.totalMeals} onChange={e => setNewSub({...newSub, totalMeals: Number(e.target.value)})} />
                          </div>
                      </div>

                      <div className="grid md:grid-cols-2 gap-4">
                          <input placeholder="الحساسية (أحمر)" className="border border-red-100 p-3 rounded-xl bg-red-50 text-red-700 font-bold" value={newSub.allergies} onChange={e => setNewSub({...newSub, allergies: e.target.value})} />
                          <select className="border p-3 rounded-xl bg-gray-50" value={newSub.deliverySlot} onChange={e => setNewSub({...newSub, deliverySlot: e.target.value as DeliverySlot})}>
                              <option value={DeliverySlot.MORNING}>صباحي (10-12)</option>
                              <option value={DeliverySlot.EVENING}>مسائي (3-5)</option>
                          </select>
                      </div>

                      <button type="submit" className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg mt-4">تفعيل العضوية والجدول</button>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Subscription as SubscriptionModel, DeliverySlot, SubscriptionPlan } from '../types';
import { dataService } from '../services/dataService';
import { Check, Clock, MapPin, Truck, Tag, Edit3, Phone } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface SubscriptionProps {
    initialPlanId?: string | null;
}

export const Subscription: React.FC<SubscriptionProps> = ({ initialPlanId }) => {
  const [step, setStep] = useState(1);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [selectedPlanId, setSelectedPlanId] = useState<string | null>(null);

  const [subData, setSubData] = useState<Partial<SubscriptionModel>>({
    deliverySlot: DeliverySlot.MORNING,
    address: '',
    phone: '',
    notes: ''
  });

  // Promo Logic
  const [promoCode, setPromoCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [appliedPromo, setAppliedPromo] = useState<string | null>(null);
  const [promoMessage, setPromoMessage] = useState('');

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchPlans = async () => {
        setPlans(await dataService.getSubscriptionPlans());
    };
    fetchPlans();
  }, []);

  // Handle Deep Linking / Initial Plan
  useEffect(() => {
      if (initialPlanId && plans.length > 0) {
          const exists = plans.some(p => p.id === initialPlanId);
          if (exists) {
              handleSelectPlan(initialPlanId);
          }
      }
  }, [initialPlanId, plans]);

  const handleSelectPlan = (id: string) => {
    setSelectedPlanId(id);
    setSubData(prev => ({ ...prev, duration: id }));
    setStep(2);
    // Reset Promo when changing plans
    setDiscount(0);
    setAppliedPromo(null);
    setPromoCode('');
    setPromoMessage('');
  };

  const handleApplyPromo = async () => {
      if (!promoCode) return;

      const promo = await dataService.verifyPromoCode(promoCode.toUpperCase(), 'SUBSCRIPTION');
      if (promo) {
          const selectedPlan = plans.find(p => p.id === selectedPlanId);
          if (selectedPlan) {
             let discVal = 0;
             if (promo.isPercentage) {
                 discVal = selectedPlan.price * (promo.discountAmount / 100);
             } else {
                 discVal = promo.discountAmount;
             }
             setDiscount(discVal);
             setAppliedPromo(promo.code);
             setPromoMessage('تم تفعيل الخصم بنجاح! 🎉');
          }
      } else {
          setPromoMessage('كود الخصم غير صالح أو غير مخصص للاشتراكات ❌');
          setDiscount(0);
          setAppliedPromo(null);
      }
  };

  const handleDetailsSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const selectedPlan = plans.find(p => p.id === selectedPlanId);

    if(subData.address && subData.phone && selectedPlanId && subData.deliverySlot && selectedPlan) {
        const finalPrice = Math.max(0, selectedPlan.price - discount);

        try {
            // Added 'id', 'status', and missing tracking properties to satisfy the 'Subscription' interface requirements.
            // dataService.saveSubscription will handle real ID generation and status initialization.
            await dataService.saveSubscription({
                id: '', // Will be updated in dataService
                status: 'active', // Default initial status
                duration: selectedPlan.durationLabel, // Store label for readability
                deliverySlot: subData.deliverySlot,
                address: subData.address,
                phone: subData.phone,
                notes: subData.notes, // Save notes
                date: new Date().toISOString(),
