};

import { Order, Subscription, SiteContent, Meal, SubscriptionPlan, PromoCode, AnalyticsData } from '../types';
import { MEALS } from '../constants';
import { db } from './firebase';
import { collection, getDocs, doc, setDoc, updateDoc, deleteDoc, getDoc, increment } from 'firebase/firestore';

// Local cache only for configuration items (Plans/Promos/Content)
let localPlans: SubscriptionPlan[] = [];
let localPromos: PromoCode[] = [];

export const dataService = {
  // Orders
  getOrders: async (): Promise<Order[]> => {
    try {
      const orders: Order[] = [];
      const querySnapshot = await getDocs(collection(db, "orders"));
      querySnapshot.forEach((doc) => {
        orders.push(doc.data() as Order);
      });
      return orders.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    } catch (e) {
      console.error("Failed to fetch orders from DB:", e);
      return [];
    }
  },

  saveOrder: async (order: Order) => {
    await setDoc(doc(db, "orders", order.id), order);
  },

  updateOrderStatus: async (id: string, status: 'pending' | 'completed' | 'cancelled') => {
    const orderRef = doc(db, "orders", id);
    await updateDoc(orderRef, { status: status });
  },

  // Subscriptions
  getSubscriptions: async (): Promise<Subscription[]> => {
    try {
      const subs: Subscription[] = [];
      const querySnapshot = await getDocs(collection(db, "subscriptions"));
      querySnapshot.forEach((doc) => {
        subs.push(doc.data() as Subscription);
      });
      return subs.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    } catch (e) {
      console.error("Failed to fetch subscriptions from DB:", e);
      return [];
    }
  },

  saveSubscription: async (sub: Subscription) => {
    const id = sub.id || `sub_${Date.now()}`;
    const subWithId = { ...sub, id, status: 'active', deliveredCount: 0, postponedCount: 0 };
    await setDoc(doc(db, "subscriptions", id), subWithId);
  },

  updateSubscription: async (id: string, updates: Partial<Subscription>) => {
    const subRef = doc(db, "subscriptions", id);
    await updateDoc(subRef, updates);
  },

  deleteSubscription: async (id: string) => {
    const subRef = doc(db, "subscriptions", id);
    await deleteDoc(subRef);
  },

  // Content
  getContent: async (): Promise<SiteContent> => {
    const defaults: SiteContent = {
        heroTitle: 'نمط حياة خفيف وصحي للجميع',
        heroSubtitle: 'انكل هيلثي هو وجهتك الأولى للوجبات الصحية الفاخرة. نجمع بين الذكاء الاصطناعي والمكونات الطبيعية 100% لنقدم لك تجربة غذائية لا تُنسى.',
        heroImage: 'https://i.ibb.co/6J8BHK9s/28.jpg',
        missionTitle: 'مهمتنا',
        missionText: 'توفير وجبات صحية فاخرة مصنوعة من مكونات طبيعية 100%. نحن نجعل الحياة الصحية بسيطة، لذيذة، ومتاحة للجميع.',
        featuresList: [
            'مكونات طبيعية 100%',
            'استشارات مدعومة بالذكاء الاصطناعي',
            'نظام اشتراك مرن',
            'توصيل دقيق في الموعد'
        ],
        contactPhone: '',
        appBannerTitle1: 'صحتك صارت',
        appBannerHighlight: 'أسهل وأقرب',
        appBannerText: 'حمل التطبيق الآن واستمتع بتجربة طلب أسرع، تتبع لخطتك الغذائية، وعروض حصرية. وجباتك الصحية بلمسة زر.',
        appBannerImage: 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?ixlib=rb-1.2.1&auto=format&fit=crop&w=600&q=80',
        privacyPolicy: 'نحن نلتزم بحماية خصوصيتك...',
        returnPolicy: 'نظراً لطبيعة المنتجات الغذائية...',
        paymentPolicy: 'نقبل الدفع نقداً عند الاستلام...',
        socialFacebook: 'https://facebook.com',
        socialInstagram: 'https://instagram.com',
        socialTwitter: 'https://twitter.com',
        linkAndroid: '',
        linkIOS: ''
    };

    try {
      const docRef = doc(db, "content", "main_content");
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const data = docSnap.data() as SiteContent;
        return { 
            ...defaults, 
            ...data, 
            featuresList: data.featuresList || defaults.featuresList,
            contactPhone: data.contactPhone || defaults.contactPhone
        };
      } else {
        try { await setDoc(docRef, defaults); } catch(err) {}
        return defaults;
      }
    } catch (e) {
      console.warn("Firebase content unavailable, using defaults.");
      return defaults;
    }
  },

  saveContent: async (content: SiteContent): Promise<boolean> => {
    try {
      await setDoc(doc(db, "content", "main_content"), content);
      return true;
    } catch (e) {
      console.warn("Failed to save content", e);
      return false;
    }
  },

  // Meals
  getMeals: async (): Promise<Meal[]> => {
    try {
      const querySnapshot = await getDocs(collection(db, "meals"));
      const meals: Meal[] = [];
      querySnapshot.forEach((doc) => {
        meals.push(doc.data() as Meal);
      });

      if (meals.length === 0) {
        try {
            for (const m of MEALS) {
                await setDoc(doc(db, "meals", m.id), m);
            }
        } catch(err) {}
        return MEALS;
      }
      return meals;
    } catch (e) {
      return MEALS;
    }
  },
  addMeal: async (meal: Meal) => {
    await setDoc(doc(db, "meals", meal.id), meal);
  },
  deleteMeal: async (id: string) => {
    await deleteDoc(doc(db, "meals", id));
  },

  // Analytics Functions
  getAnalytics: async (): Promise<AnalyticsData> => {
      const defaultAnalytics: AnalyticsData = {
          totalVisits: 0,
          androidClicks: 0,
          iosClicks: 0,
          mealViews: {},
          visitHours: {}
      };

      try {
          const docRef = doc(db, "analytics", "main_stats");
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) {
              const data = docSnap.data();
              return {
                  ...defaultAnalytics,
                  ...data,
                  // Ensure objects exist if they are missing in DB
                  mealViews: data.mealViews || {},
                  visitHours: data.visitHours || {}
              } as AnalyticsData;
          } else {
              // Initialize if not exists
              await setDoc(docRef, defaultAnalytics);
              return defaultAnalytics;
          }
      } catch (e) {
          console.error("Error fetching analytics", e);
          return defaultAnalytics;
      }
  },

  logVisit: async () => {
      // Use setDoc with merge to safely update counters
      try {
          const docRef = doc(db, "analytics", "main_stats");
          const currentHour = new Date().getHours();
          await setDoc(docRef, {
              totalVisits: increment(1),
              visitHours: {
                  [currentHour]: increment(1)
              }
          }, { merge: true });
      } catch(e) { console.error("Track visit failed", e) }
  },

  logMealView: async (mealId: string) => {
      try {
          const docRef = doc(db, "analytics", "main_stats");
          await setDoc(docRef, {
              mealViews: {
                  [mealId]: increment(1)
              }
          }, { merge: true });
      } catch(e) { console.error("Track meal view failed", e) }
  },

  logAppClick: async (platform: 'android' | 'ios') => {
      try {
          const docRef = doc(db, "analytics", "main_stats");
          await setDoc(docRef, {
              [platform === 'android' ? 'androidClicks' : 'iosClicks']: increment(1)
          }, { merge: true });
      } catch(e) { console.error("Track app click failed", e) }
  },

  // Subscription Plans
  getSubscriptionPlans: async (): Promise<SubscriptionPlan[]> => {
    let plans: SubscriptionPlan[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "plans"));
      querySnapshot.forEach((doc) => {
        plans.push(doc.data() as SubscriptionPlan);
      });
    } catch (e) {}

    localPlans.forEach(lp => {
        const idx = plans.findIndex(p => p.id === lp.id);
        if (idx >= 0) plans[idx] = lp;
        else plans.push(lp);
    });

    if (plans.length === 0) {
         return [];
    }
    return plans;
  },

  saveSubscriptionPlan: async (plan: SubscriptionPlan) => {
    const existingIndex = localPlans.findIndex(p => p.id === plan.id);
    if (existingIndex >= 0) localPlans[existingIndex] = plan;
    else localPlans.push(plan);
    try { await setDoc(doc(db, "plans", plan.id), plan); } catch (e) {}
  },

  deleteSubscriptionPlan: async (id: string) => {
    localPlans = localPlans.filter(p => p.id !== id);
    try { await deleteDoc(doc(db, "plans", id)); } catch (e) {}
  },

  // Promo Codes
  getPromoCodes: async (): Promise<PromoCode[]> => {
    let promos: PromoCode[] = [];
    try {
      const querySnapshot = await getDocs(collection(db, "promos"));
      querySnapshot.forEach((doc) => {
        promos.push(doc.data() as PromoCode);
      });
    } catch (e) {}
    localPromos.forEach(lp => {
         const idx = promos.findIndex(p => p.id === lp.id);
         if (idx >= 0) promos[idx] = lp;
         else promos.push(lp);
    });
    return promos;
  },

  savePromoCode: async (promo: PromoCode) => {
    const idx = localPromos.findIndex(p => p.id === promo.id);
    if (idx >= 0) localPromos[idx] = promo;
    else localPromos.push(promo);
    try { await setDoc(doc(db, "promos", promo.id), promo); } catch (e) {}
  },

  deletePromoCode: async (id: string) => {
    localPromos = localPromos.filter(p => p.id !== id);
    try { await deleteDoc(doc(db, "promos", id)); } catch (e) {}
  },

  verifyPromoCode: async (code: string, type: 'MEALS' | 'SUBSCRIPTION'): Promise<PromoCode | null> => {
     const allPromos = await dataService.getPromoCodes();
     return allPromos.find(p => p.code === code && p.isActive && p.type === type) || null;
  }
};

import React, { useState, useEffect } from 'react';
import { Subscription, UserProfile, SubscriptionPlan, DeliverySlot, Meal, DayConfig } from '../types';
import { dataService } from '../services/dataService';
import { ChefHat, LogOut, Clock, MapPin, Phone, Truck, CheckCircle, AlertTriangle, Calendar, User, Info, RefreshCcw, Plus, Trash2, X, ChevronDown, ChevronUp, CalendarDays, Edit3, Hash } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface ChefDashboardProps {
  onLogout: () => void;
}

export const ChefDashboard: React.FC<ChefDashboardProps> = ({ onLogout }) => {
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [meals, setMeals] = useState<Meal[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'active' | 'out-for-delivery' | 'delivered'>('all');

  // Modals States
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDayModal, setShowDayModal] = useState(false);
  const [expandedSubId, setExpandedSubId] = useState<string | null>(null);

  // Day Editing State
  const [activeDayEdit, setActiveDayEdit] = useState<{subId: string, date: string} | null>(null);
  const [dayEditForm, setDayEditForm] = useState<DayConfig>({ mealId: '', count: 1, status: 'pending' });

  const [newSub, setNewSub] = useState({
      customerName: '',
      phone: '',
      address: '',
      planId: '',
      totalMeals: 30,
      deliverySlot: DeliverySlot.MORNING,
      notes: '',
      allergies: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [subsData, plansData, mealsData] = await Promise.all([
        dataService.getSubscriptions(),
        dataService.getSubscriptionPlans(),
        dataService.getMeals()
    ]);
    setSubscriptions(subsData);
    setPlans(plansData);
    setMeals(mealsData);
    setLoading(false);
  };

  const handleUpdateStatus = async (id: string, updates: Partial<Subscription>) => {
      try {
          await dataService.updateSubscription(id, updates);
          setSubscriptions(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
      } catch (err) {
          alert('فشل في تحديث الحالة');
      }
  };

  const handleDeleteSubscription = async (id: string) => {
      if (confirm('هل أنت متأكد من حذف هذا الاشتراك نهائياً من النظام؟ لا يمكن التراجع عن هذه الخطوة.')) {
          try {
              await dataService.deleteSubscription(id);
              setSubscriptions(prev => prev.filter(s => s.id !== id));
              alert('تم حذف الاشتراك بنجاح');
          } catch (err) {
              alert('حدث خطأ أثناء محاولة الحذف');
          }
      }
  };

  const handleAddSub = async (e: React.FormEvent) => {
      e.preventDefault();
      const selectedPlan = plans.find(p => p.id === newSub.planId);
      if (!selectedPlan) { alert('يرجى اختيار باقة'); return; }

      const subscription: Subscription = {
          id: `sub_chef_${Date.now()}`,
          date: new Date().toISOString().split('T')[0],
          address: newSub.address,
          phone: newSub.phone,
          deliverySlot: newSub.deliverySlot,
          planTitle: selectedPlan.title,
          pricePaid: selectedPlan.price,
          duration: selectedPlan.durationLabel,
          status: 'active',
          totalMeals: Number(newSub.totalMeals),
          deliveredCount: 0,
          postponedCount: 0,
          notes: newSub.notes,
          dailyConfigs: {},
          user: {
              id: newSub.phone,
              name: newSub.customerName,
              phone: newSub.phone,
              allergies: newSub.allergies,
              hasProfile: true,
              age: '', gender: '', height: '', weight: '', goal: ''
          }
      };

      await dataService.saveSubscription(subscription);
      setShowAddModal(false);
      setNewSub({ customerName: '', phone: '', address: '', planId: '', totalMeals: 30, deliverySlot: DeliverySlot.MORNING, notes: '', allergies: '' });
      loadData();
  };

  const handleDayClick = (sub: Subscription, date: string) => {
      const existing = sub.dailyConfigs?.[date] || { mealId: '', count: 1, status: 'pending' };
      setActiveDayEdit({ subId: sub.id, date });
      setDayEditForm(existing);
      setShowDayModal(true);
  };

  const saveDayConfig = async () => {
      if (!activeDayEdit) return;
      const sub = subscriptions.find(s => s.id === activeDayEdit.subId);
      if (!sub) return;

      const newConfigs = { ...sub.dailyConfigs, [activeDayEdit.date]: dayEditForm };
      await handleUpdateStatus(sub.id, { dailyConfigs: newConfigs });
      setShowDayModal(false);
  };

  const handlePostpone = async (sub: Subscription) => {
      if(confirm('سيتم تأجيل وجبة اليوم وإضافة يوم إضافي للاشتراك. متابعة؟')) {
          const newPostponedCount = (sub.postponedCount || 0) + 1;
          const todayKey = new Date().toISOString().split('T')[0];

          const newConfigs = { ...sub.dailyConfigs };
          if (newConfigs[todayKey]) {
              newConfigs[todayKey].status = 'postponed';
          } else {
              newConfigs[todayKey] = { mealId: '', count: 0, status: 'postponed' };
          }

          await handleUpdateStatus(sub.id, {
              status: 'active',
              postponedCount: newPostponedCount,
              dailyConfigs: newConfigs,
              departureTime: '',
              arrivalTime: ''
          });
          alert('تم التأجيل وتمديد المدة');
      }
  };

  const renderMonthlySchedule = (sub: Subscription) => {
      const startDate = new Date(sub.date);
      // Monthly view is 30 days + postponed days extension
      const totalDaysToShow = 30 + (sub.postponedCount || 0);
      const days = Array.from({ length: totalDaysToShow });

      return (
          <div className="mt-4 border-t pt-4 animate-fade-in">
              <div className="flex justify-between items-center mb-4">
                  <h4 className="font-bold text-uh-dark flex items-center gap-2">
                      <CalendarDays size={18} className="text-uh-green" />
                      الجدول الزمني (ممتد لـ {totalDaysToShow} يوم)
                  </h4>
                  <p className="text-xs text-gray-400">اضغط على اليوم لتحديد الوجبات والعدد</p>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-2">
                  {days.map((_, idx) => {
                      const currentDate = new Date(startDate);
                      currentDate.setDate(startDate.getDate() + idx);
                      const dateKey = currentDate.toISOString().split('T')[0];
                      const config = sub.dailyConfigs?.[dateKey];
                      const isToday = currentDate.toDateString() === new Date().toDateString();
                      const isPast = currentDate < new Date(new Date().setHours(0,0,0,0));
                      const meal = meals.find(m => m.id === config?.mealId);

                      return (
                          <div 
                            key={idx} 
                            onClick={() => handleDayClick(sub, dateKey)}
                            className={`p-2 rounded-xl text-center border cursor-pointer transition-all hover:scale-105 ${
                                isToday ? 'bg-uh-gold/10 border-uh-gold' : 
                                config?.status === 'postponed' ? 'bg-red-50 border-red-200' :
                                isPast ? 'bg-gray-50 border-gray-100' : 'bg-white border-gray-100'
                            }`}
                          >
                              <div className="text-[10px] text-gray-400 mb-1">
                                  {currentDate.toLocaleDateString('ar-EG', { day: 'numeric', month: 'short' })}
                              </div>
                              <div className="text-xs font-bold">يوم {idx + 1}</div>

                              {config && config.count > 0 && (
                                  <div className="mt-1">
                                      <div className="text-[10px] bg-uh-green/10 text-uh-greenDark rounded-full px-1 truncate font-bold">
                                          {meal ? meal.name : 'وجبة مخصصة'}
                                      </div>
                                      <div className="text-[10px] font-bold text-uh-dark">العدد: {config.count}</div>
                                  </div>
                              )}

                              {config?.status === 'postponed' && (
                                  <div className="text-[8px] text-red-500 font-bold mt-1">مؤجل ⏳</div>
                              )}
                              {isToday && <div className="text-[8px] bg-uh-green text-white rounded mt-1 px-1">اليوم</div>}
                          </div>
                      );
                  })}
              </div>
          </div>
      );
  };

  const filteredSubs = subscriptions.filter(s => filter === 'all' || s.status === filter);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-arabic" dir="rtl">
      {/* Header */}
      <header className="bg-uh-dark text-white p-4 shadow-lg flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
              <div className="bg-uh-green p-2 rounded-lg"><ChefHat size={24} /></div>
              <h1 className="text-xl font-bold">إدارة مطبخ Uncle Healthy</h1>
          </div>
          <div className="flex items-center gap-4">
              <button onClick={() => setShowAddModal(true)} className="bg-uh-gold text-uh-dark px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-yellow-500 transition shadow-sm"><Plus size={20}/> <span>إضافة اشتراك</span></button>
              <button onClick={onLogout} className="text-red-400 hover:text-red-300 transition font-bold flex items-center gap-2"><LogOut size={20}/> <span>خروج</span></button>
          </div>
      </header>

      <main className="flex-1 container mx-auto p-4 md:p-8 space-y-6">

          {/* Dashboard Stats Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات الموزعة</p>
                  <p className="text-2xl font-bold text-uh-green">{subscriptions.reduce((sum, s) => sum + (s.deliveredCount || 0), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات المتبقية</p>
                  <p className="text-2xl font-bold text-uh-dark">{subscriptions.reduce((sum, s) => sum + (s.totalMeals - (s.deliveredCount || 0)), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الطلبات النشطة</p>
                  <p className="text-2xl font-bold text-blue-500">{subscriptions.filter(s => s.status !== 'delivered').length}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">أيام التأجيل</p>
                  <p className="text-2xl font-bold text-red-500">{subscriptions.reduce((sum, s) => sum + (s.postponedCount || 0), 0)}</p>
              </div>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
              {['all', 'active', 'out-for-delivery', 'delivered'].map((f) => (
                  <button key={f} onClick={() => setFilter(f as any)} className={`px-4 py-2 rounded-full text-xs font-bold transition whitespace-nowrap ${filter === f ? 'bg-uh-dark text-white' : 'bg-white text-gray-500 border hover:bg-gray-50'}`}>
                      {f === 'all' ? 'الكل' : f === 'active' ? 'بانتظار التجهيز' : f === 'out-for-delivery' ? 'في الطريق' : 'تم التسليم'}
                  </button>
              ))}
          </div>

          <div className="grid gap-6">
              {filteredSubs.map(sub => {
                  const customer = sub.user;
                  const isExpanded = expandedSubId === sub.id;
                  const todayKey = new Date().toISOString().split('T')[0];
                  const todayConfig = sub.dailyConfigs?.[todayKey];
                  const todayMeal = meals.find(m => m.id === todayConfig?.mealId);
                  const remaining = sub.totalMeals - (sub.deliveredCount || 0);

                  return (
                      <div key={sub.id} className={`bg-white rounded-3xl shadow-sm border overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-uh-green' : 'border-gray-100'}`}>
                          <div className="grid md:grid-cols-3">

                              <div className="p-6 border-l border-gray-50 relative group">
                                  <button 
                                    onClick={() => handleDeleteSubscription(sub.id)}
                                    className="absolute top-2 left-2 p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-full transition opacity-0 group-hover:opacity-100"
                                    title="حذف الاشتراك نهائياً"
                                  >
                                      <Trash2 size={18} />
                                  </button>

                                  <div className="flex items-center gap-3 mb-4 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                      <div className="w-12 h-12 bg-uh-cream rounded-full flex items-center justify-center text-uh-dark font-bold"><User size={24}/></div>
                                      <div>
                                          <h3 className="font-bold text-lg text-uh-dark">{customer?.name}</h3>
                                          <div className="flex gap-2 items-center">
                                              <span className="text-[10px] bg-uh-gold/20 text-uh-greenDark px-2 py-0.5 rounded-full font-bold">{sub.planTitle}</span>
                                              <span className="text-[10px] bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full font-bold">بدأ في: {sub.date}</span>
                                          </div>
                                      </div>
                                  </div>
                                  <div className="space-y-2 text-sm">
                                      <a href={`tel:${sub.phone}`} className="flex items-center gap-2 text-blue-600 font-bold"><Phone size={14}/> {sub.phone}</a>
                                      <p className="text-gray-500 flex items-start gap-2"><MapPin size={14} className="mt-1 flex-shrink-0"/> {sub.address}</p>
                                  </div>
                              </div>

                              <div className="p-6 bg-gray-50/50 border-l border-gray-50 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                  <div className="flex justify-between items-start mb-4">
                                      <h4 className="text-xs font-bold text-gray-400 uppercase">مهمة المطبخ لليوم</h4>
                                      <div className="flex gap-1">
                                          <span className="text-[10px] bg-white border border-gray-200 px-2 py-0.5 rounded-full font-bold">المتبقي: {remaining}</span>
                                          {isExpanded ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                      </div>
                                  </div>

                                  {todayConfig && todayConfig.count > 0 ? (
                                      <div className="bg-white p-3 rounded-2xl shadow-sm border border-uh-green/20">
                                          <div className="flex items-center gap-3">
                                              {todayMeal && <img src={todayMeal.image} className="w-10 h-10 rounded-lg object-cover" alt=""/>}
                                              <div>
                                                  <p className="font-bold text-sm">{todayMeal ? todayMeal.name : 'وجبة مخصصة'}</p>
                                                  <p className="text-uh-green font-bold text-xs">العدد لليوم: {todayConfig.count}</p>
                                              </div>
                                          </div>
                                      </div>
                                  ) : (
                                      <div className="text-center py-4 text-gray-400 text-xs italic">لا توجد وجبات مبرمجة لليوم - اضغط لبرمجة الجدول</div>
                                  )}

                                  <div className="mt-3 p-2 rounded-xl bg-red-50 text-red-700 text-xs font-bold">
                                      ⚠️ {customer?.allergies || 'لا توجد ملاحظات صحية'}
                                  </div>
                              </div>

                              <div className="p-6 flex flex-col justify-between">
                                  <div className="flex justify-between items-center mb-4">
                                      <span className="text-[10px] text-gray-400 font-bold uppercase">الحالة: {sub.status}</span>
                                      <div className="flex items-center gap-1 text-uh-greenDark font-bold text-xs"><Clock size={12}/> {sub.deliverySlot}</div>
                                  </div>

                                  <div className="grid grid-cols-2 gap-2">
                                      {sub.status !== 'delivered' ? (
                                          <>
                                              {sub.status === 'active' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'out-for-delivery', departureTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}) })} className="col-span-2 bg-uh-dark text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-black transition shadow-sm"><Truck size={16}/> خروج الطلب</button>
                                              )}
                                              {sub.status === 'out-for-delivery' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'delivered', arrivalTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}), deliveredCount: (sub.deliveredCount || 0) + (todayConfig?.count || 1) })} className="col-span-2 bg-uh-green text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-uh-greenDark transition shadow-md"><CheckCircle size={16}/> تم التسليم</button>
                                              )}
                                              <button onClick={() => handlePostpone(sub)} className="col-span-2 border border-red-200 text-red-500 py-2 rounded-xl text-xs font-bold hover:bg-red-50 transition">تأجيل لليوم (تمديد الاشتراك)</button>
                                          </>
                                      ) : (
                                          <div className="col-span-2 bg-green-50 text-green-700 py-2 rounded-xl text-center font-bold text-xs border border-green-100 animate-pulse">اكتمل التوصيل اليوم ✅</div>
                                      )}
                                  </div>
                              </div>
                          </div>

                          {isExpanded && <div className="p-6 bg-gray-50/20 border-t border-gray-100">{renderMonthlySchedule(sub)}</div>}
                      </div>
                  );
              })}
              {filteredSubs.length === 0 && (
                  <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-300 text-gray-400">لا توجد اشتراكات مطابقة للفلتر المختار</div>
              )}
          </div>
      </main>

      {/* Day Editing Modal */}
      {showDayModal && activeDayEdit && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
              <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl relative">
                  <div className="flex justify-between items-center mb-6">
                      <div className="flex items-center gap-2 text-uh-dark">
                          <Edit3 className="text-uh-green" />
                          <h3 className="font-bold text-xl">برمجة يوم: {activeDayEdit.date}</h3>
                      </div>
                      <button onClick={() => setShowDayModal(false)} className="text-gray-400 hover:text-uh-dark"><X/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-sm font-bold mb-2">اختر صنف الوجبة من المتجر</label>
                          <select 
                            className="w-full border p-4 rounded-xl bg-gray-50 outline-none focus:ring-2 focus:ring-uh-green transition"
                            value={dayEditForm.mealId}
                            onChange={e => setDayEditForm({...dayEditForm, mealId: e.target.value})}
                          >
                              <option value="">اختر وجبة من القائمة...</option>
                              {meals.map(m => <option key={m.id} value={m.id}>{m.name} - {m.macros.calories} سعرة</option>)}
                          </select>
                      </div>

                      <div>
                          <label className="block text-sm font-bold mb-2 flex items-center gap-2"><Hash size={16} className="text-uh-gold"/> عدد الوجبات لهذا اليوم</label>
                          <div className="flex items-center gap-6 bg-gray-100 p-4 rounded-2xl justify-center">
                              <button onClick={() => setDayEditForm({...dayEditForm, count: Math.max(0, dayEditForm.count - 1)})} className="bg-white w-10 h-10 rounded-full shadow-md flex items-center justify-center hover:bg-gray-50 transition"><Minus size={18}/></button>
                              <span className="text-2xl font-bold w-12 text-center text-uh-dark">{dayEditForm.count}</span>
                              <button onClick={() => setDayEditForm({...dayEditForm, count: dayEditForm.count + 1})} className="bg-white w-10 h-10 rounded-full shadow-md flex items-center justify-center hover:bg-gray-50 transition"><Plus size={18}/></button>
                          </div>
                      </div>

                      <div className="bg-uh-cream/50 p-4 rounded-xl border border-uh-cream text-xs text-uh-greenDark leading-relaxed">
                          ⚠️ سيتم خصم عدد الوجبات المحددة أعلاه من الرصيد الكلي للزبون عند تأكيد التوصيل في هذا التاريخ.
                      </div>

                      <button onClick={saveDayConfig} className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg hover:bg-uh-greenDark transition transform hover:-translate-y-1">حفظ إعدادات اليوم</button>
                  </div>
              </div>
          </div>
      )}

      {/* Add Subscription Modal */}
      {showAddModal && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-xl p-8 shadow-2xl my-8 relative">
                  <div className="flex justify-between items-center mb-6 border-b pb-4">
                      <h3 className="text-xl font-bold flex items-center gap-2"><Plus className="text-uh-green" /> تفعيل اشتراك زبون جديد</h3>
                      <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-red-500 transition"><X /></button>
                  </div>

                  <form onSubmit={handleAddSub} className="space-y-4">
                      <div className="grid md:grid-cols-2 gap-4">
                          <input required placeholder="اسم الزبون الكامل" className="border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" value={newSub.customerName} onChange={e => setNewSub({...newSub, customerName: e.target.value})} />
                          <input required type="tel" placeholder="رقم هاتف الزبون" className="border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" value={newSub.phone} onChange={e => setNewSub({...newSub, phone: e.target.value})} />
                      </div>
                      <textarea required placeholder="العنوان بالتفصيل (المدينة، الحي، الشارع، البناية)" className="w-full border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" rows={2} value={newSub.address} onChange={e => setNewSub({...newSub, address: e.target.value})} />

                      <div className="grid md:grid-cols-3 gap-4">
                          <div className="md:col-span-2">
                              <label className="text-xs font-bold text-gray-400 mb-1 block uppercase">باقة الاشتراك</label>
                              <select required className="w-full border p-4 rounded-xl bg-gray-50 outline-none" value={newSub.planId} onChange={e => setNewSub({...newSub, planId: e.target.value})}>
                                  <option value="">اختر باقة...</option>
                                  {plans.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="text-xs font-bold text-gray-400 mb-1 block uppercase">عدد الوجبات الكلي</label>
                              <input type="number" className="w-full border p-4 rounded-xl bg-gray-50 outline-none" value={newSub.totalMeals} onChange={e => setNewSub({...newSub, totalMeals: Number(e.target.value)})} />
                          </div>
                      </div>

                      <div className="grid md:grid-cols-2 gap-4">
                          <div>
                              <label className="text-xs font-bold text-red-400 mb-1 block uppercase">حساسية / استبدال (اختياري)</label>
                              <input placeholder="مثال: بدون بصل" className="w-full border border-red-100 p-4 rounded-xl bg-red-50 text-red-700 font-bold placeholder-red-300" value={newSub.allergies} onChange={e => setNewSub({...newSub, allergies: e.target.value})} />
                          </div>
                          <div>
                              <label className="text-xs font-bold text-gray-400 mb-1 block uppercase">فترة التوصيل</label>
                              <select className="w-full border p-4 rounded-xl bg-gray-50 outline-none" value={newSub.deliverySlot} onChange={e => setNewSub({...newSub, deliverySlot: e.target.value as DeliverySlot})}>
                                  <option value={DeliverySlot.MORNING}>صباحي (10-12)</option>
                                  <option value={DeliverySlot.EVENING}>مسائي (3-5)</option>
                              </select>
                          </div>
                      </div>

                      <button type="submit" className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg mt-4 hover:bg-uh-greenDark transition-all active:scale-95">حفظ وتفعيل عضوية الزبون</button>
                  </form>
              </div>
          </div>
      )}

      <div className="mt-10 p-4 text-center text-gray-400 text-xs">
          نظام Uncle Healthy للمطابخ الذكية © 2025
      </div>
    </div>
  );
};

const Minus: React.FC<{size?: number}> = ({size = 24}) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line></svg>
);

export interface Meal {
  id: string;
  name: string;
  description: string;
  image: string;
  price: number;
  macros: {
    protein: number;
    carbs: number;
    fats: number;
    calories: number;
  };
  ingredients: string[];
  instructions: string[];
}

export interface DayConfig {
  mealId: string;
  count: number;
  status: 'pending' | 'delivered' | 'postponed';
}

export interface UserProfile {
  id: string;
  password?: string;
  name: string;
  age: string;
  gender: string;
  height: string;
  weight: string;
  goal: string;
  allergies: string;
  phone: string;
  hasProfile: boolean;
  savedPlan?: DailyPlan[];
  isAdmin?: boolean;
  isChef?: boolean;
  isEmployee?: boolean;
}

export enum SubscriptionDuration {
  WEEKLY = 'Weekly',
  MONTHLY = 'Monthly'
}

export enum DeliverySlot {
  MORNING = '10:00 - 12:00',
  EVENING = '15:00 - 17:00'
}

export interface SubscriptionPlan {
  id: string;
  title: string;
  price: number;
  image?: string;
  features: string[];
  durationLabel: string;
  isPopular?: boolean;
}

export interface PromoCode {
  id: string;
  code: string;
  type: 'MEALS' | 'SUBSCRIPTION';
  discountAmount: number;
  isPercentage: boolean;
  isActive: boolean;
}

export interface Subscription {
  id: string;
  duration: string;
  deliverySlot: DeliverySlot;
  address: string;
  phone: string;
  notes?: string; 
  user?: UserProfile;
  date: string;
  planTitle?: string;
  pricePaid?: number;
  // Enhanced tracking
  totalMeals: number;
  deliveredCount: number;
  postponedCount: number;
  dailyConfigs?: Record<string, DayConfig>; // Key is date string YYYY-MM-DD
  departureTime?: string;
  arrivalTime?: string;
  status: 'active' | 'postponed' | 'delivered' | 'out-for-delivery' | 'cancelled';
}

export interface DailyPlan {
  day: string;
  breakfast: Meal;
  lunch: Meal;
  dinner: Meal;
}

export interface CartItem extends Meal {
  quantity: number;
}

export interface Order {
  id: string;
  user: UserProfile;
  items: CartItem[];
  total: number;
  address: string;
  phone: string;
  date: string;
  status: 'pending' | 'completed' | 'cancelled';
  promoCode?: string;
  discountApplied?: number;
  tax?: number;
}

export interface SiteContent {
  heroTitle: string;
  heroSubtitle: string;
  heroImage: string;
  missionTitle: string;
  missionText: string;
  featuresList: string[];
  contactPhone: string;
  appBannerTitle1?: string;
  appBannerHighlight?: string;
  appBannerText?: string;
  appBannerImage?: string;
  privacyPolicy: string;
  returnPolicy: string;
  paymentPolicy: string;
  socialFacebook: string;
  socialInstagram: string;
  socialTwitter: string;
  linkAndroid: string;
  linkIOS: string;
}

export interface AnalyticsData {
  totalVisits: number;
  androidClicks: number;
  iosClicks: number;
  mealViews: Record<string, number>;
  visitHours: Record<string, number>;
}

export type PageView = 'HOME' | 'LOGIN' | 'ONBOARDING' | 'STORE' | 'PROFILE' | 'SUBSCRIPTION' | 'MEAL_DETAIL' | 'CART' | 'ADMIN' | 'CHEF' | 'PRIVACY_POLICY' | 'RETURN_POLICY' | 'PAYMENT_POLICY';

import { UserProfile } from '../types';
import { db } from './firebase';
import { doc, getDoc, setDoc, collection, getDocs } from 'firebase/firestore';

export const authService = {
  // Save a new user
  register: async (user: UserProfile): Promise<UserProfile> => {
    try {
      await setDoc(doc(db, "users", user.phone), user);
      return user;
    } catch (e) {
      console.warn("Registration to DB failed, using local session only.");
      return user;
    }
  },

  // Find user by phone (or admin email) and password
  login: async (identifier: string, password: string): Promise<UserProfile | null> => {
    // Admin Check
    if (identifier === 'admin@uncle.com' && password === '00000000') {
        return {
            id: 'admin',
            name: 'المدير العام',
            phone: '00000000',
            hasProfile: true,
            isAdmin: true,
            age: '', gender: '', height: '', weight: '', goal: '', allergies: ''
        };
    }

    // Chef Check
    if (identifier === 'chef@uncle.com' && password === '00000000') {
        return {
            id: 'chef',
            name: 'الشيف الرئيسي',
            phone: '00000000',
            hasProfile: true,
            isChef: true,
            age: '', gender: '', height: '', weight: '', goal: '', allergies: ''
        };
    }

    // Employee Check
    if (identifier === 'self@uncle.com' && password === '00000000') {
        return {
            id: 'employee_01',
            name: 'موظف انكل',
            phone: '00000000',
            hasProfile: true,
            isEmployee: true,
            age: '', gender: '', height: '', weight: '', goal: '', allergies: ''
        };
    }

    // Regular User Login (Firestore lookup by phone)
    try {
      const docRef = doc(db, "users", identifier);
      const docSnap = await getDoc(docRef);

      if (docSnap.exists()) {
        const userData = docSnap.data() as UserProfile;
        if (userData.password === password) {
            return userData;
        }
      }
      return null;
    } catch (e) {
      console.warn("Login failed due to DB error or invalid credentials");
      return null;
    }
  },

  getAllUsers: async (): Promise<UserProfile[]> => {
    try {
      const querySnapshot = await getDocs(collection(db, "users"));
      const users: UserProfile[] = [];
      querySnapshot.forEach((doc) => {
        users.push(doc.data() as UserProfile);
      });
      return users;
    } catch (e) {
        console.warn("Failed to fetch users list");
        return [];
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Subscription, UserProfile, SubscriptionPlan, DeliverySlot, Meal, DayConfig } from '../types';
import { dataService } from '../services/dataService';
import { ChefHat, LogOut, Clock, MapPin, Phone, Truck, CheckCircle, AlertTriangle, Calendar, User, Info, RefreshCcw, Plus, Trash2, X, ChevronDown, ChevronUp, CalendarDays, Edit3, Hash } from 'lucide-react';
import { OptimizedImage } from './OptimizedImage';

interface ChefDashboardProps {
  onLogout: () => void;
  user: UserProfile;
}

export const ChefDashboard: React.FC<ChefDashboardProps> = ({ onLogout, user }) => {
  const [subscriptions, setSubscriptions] = useState<Subscription[]>([]);
  const [plans, setPlans] = useState<SubscriptionPlan[]>([]);
  const [meals, setMeals] = useState<Meal[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'active' | 'out-for-delivery' | 'delivered'>('all');

  // Modals States
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDayModal, setShowDayModal] = useState(false);
  const [expandedSubId, setExpandedSubId] = useState<string | null>(null);

  // Role Permission Flags
  const isEmployee = user.isEmployee;

  // Day Editing State
  const [activeDayEdit, setActiveDayEdit] = useState<{subId: string, date: string} | null>(null);
  const [dayEditForm, setDayEditForm] = useState<DayConfig>({ mealId: '', count: 1, status: 'pending' });

  const [newSub, setNewSub] = useState({
      customerName: '',
      phone: '',
      address: '',
      planId: '',
      totalMeals: 30,
      deliverySlot: DeliverySlot.MORNING,
      notes: '',
      allergies: ''
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [subsData, plansData, mealsData] = await Promise.all([
        dataService.getSubscriptions(),
        dataService.getSubscriptionPlans(),
        dataService.getMeals()
    ]);
    setSubscriptions(subsData);
    setPlans(plansData);
    setMeals(mealsData);
    setLoading(false);
  };

  const handleUpdateStatus = async (id: string, updates: Partial<Subscription>) => {
      try {
          await dataService.updateSubscription(id, updates);
          setSubscriptions(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
      } catch (err) {
          alert('فشل في تحديث الحالة');
      }
  };

  const handleDeleteSubscription = async (id: string) => {
      if (isEmployee) return;
      if (confirm('هل أنت متأكد من حذف هذا الاشتراك نهائياً من النظام؟ لا يمكن التراجع عن هذه الخطوة.')) {
          try {
              await dataService.deleteSubscription(id);
              setSubscriptions(prev => prev.filter(s => s.id !== id));
              alert('تم حذف الاشتراك بنجاح');
          } catch (err) {
              alert('حدث خطأ أثناء محاولة الحذف');
          }
      }
  };

  const handleAddSub = async (e: React.FormEvent) => {
      if (isEmployee) return;
      e.preventDefault();
      const selectedPlan = plans.find(p => p.id === newSub.planId);
      if (!selectedPlan) { alert('يرجى اختيار باقة'); return; }

      const subscription: Subscription = {
          id: `sub_chef_${Date.now()}`,
          date: new Date().toISOString().split('T')[0],
          address: newSub.address,
          phone: newSub.phone,
          deliverySlot: newSub.deliverySlot,
          planTitle: selectedPlan.title,
          pricePaid: selectedPlan.price,
          duration: selectedPlan.durationLabel,
          status: 'active',
          totalMeals: Number(newSub.totalMeals),
          deliveredCount: 0,
          postponedCount: 0,
          notes: newSub.notes,
          dailyConfigs: {},
          user: {
              id: newSub.phone,
              name: newSub.customerName,
              phone: newSub.phone,
              allergies: newSub.allergies,
              hasProfile: true,
              age: '', gender: '', height: '', weight: '', goal: ''
          }
      };

      await dataService.saveSubscription(subscription);
      setShowAddModal(false);
      setNewSub({ customerName: '', phone: '', address: '', planId: '', totalMeals: 30, deliverySlot: DeliverySlot.MORNING, notes: '', allergies: '' });
      loadData();
  };

  const handleDayClick = (sub: Subscription, date: string) => {
      if (isEmployee) return; // Employee cannot edit daily configs
      const existing = sub.dailyConfigs?.[date] || { mealId: '', count: 1, status: 'pending' };
      setActiveDayEdit({ subId: sub.id, date });
      setDayEditForm(existing);
      setShowDayModal(true);
  };

  const saveDayConfig = async () => {
      if (!activeDayEdit || isEmployee) return;
      const sub = subscriptions.find(s => s.id === activeDayEdit.subId);
      if (!sub) return;

      const newConfigs = { ...sub.dailyConfigs, [activeDayEdit.date]: dayEditForm };
      await handleUpdateStatus(sub.id, { dailyConfigs: newConfigs });
      setShowDayModal(false);
  };

  const handlePostpone = async (sub: Subscription) => {
      if(confirm('سيتم تأجيل وجبة اليوم وإضافة يوم إضافي للاشتراك. متابعة؟')) {
          const newPostponedCount = (sub.postponedCount || 0) + 1;
          const todayKey = new Date().toISOString().split('T')[0];

          const newConfigs = { ...sub.dailyConfigs };
          if (newConfigs[todayKey]) {
              newConfigs[todayKey].status = 'postponed';
          } else {
              newConfigs[todayKey] = { mealId: '', count: 0, status: 'postponed' };
          }

          await handleUpdateStatus(sub.id, {
              status: 'active',
              postponedCount: newPostponedCount,
              dailyConfigs: newConfigs,
              departureTime: '',
              arrivalTime: ''
          });
          alert('تم التأجيل وتمديد المدة');
      }
  };

  const renderMonthlySchedule = (sub: Subscription) => {
      const startDate = new Date(sub.date);
      const totalDaysToShow = 30 + (sub.postponedCount || 0);
      const days = Array.from({ length: totalDaysToShow });

      return (
          <div className="mt-4 border-t pt-4 animate-fade-in">
              <div className="flex justify-between items-center mb-4">
                  <h4 className="font-bold text-uh-dark flex items-center gap-2">
                      <CalendarDays size={18} className="text-uh-green" />
                      الجدول الزمني (ممتد لـ {totalDaysToShow} يوم)
                  </h4>
                  {!isEmployee && <p className="text-xs text-gray-400">اضغط على اليوم لتحديد الوجبات والعدد</p>}
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-2">
                  {days.map((_, idx) => {
                      const currentDate = new Date(startDate);
                      currentDate.setDate(startDate.getDate() + idx);
                      const dateKey = currentDate.toISOString().split('T')[0];
                      const config = sub.dailyConfigs?.[dateKey];
                      const isToday = currentDate.toDateString() === new Date().toDateString();
                      const isPast = currentDate < new Date(new Date().setHours(0,0,0,0));
                      const meal = meals.find(m => m.id === config?.mealId);

                      return (
                          <div 
                            key={idx} 
                            onClick={() => handleDayClick(sub, dateKey)}
                            className={`p-2 rounded-xl text-center border transition-all ${!isEmployee ? 'cursor-pointer hover:scale-105' : ''} ${
                                isToday ? 'bg-uh-gold/10 border-uh-gold' : 
                                config?.status === 'postponed' ? 'bg-red-50 border-red-200' :
                                isPast ? 'bg-gray-50 border-gray-100' : 'bg-white border-gray-100'
                            }`}
                          >
                              <div className="text-[10px] text-gray-400 mb-1">
                                  {currentDate.toLocaleDateString('ar-EG', { day: 'numeric', month: 'short' })}
                              </div>
                              <div className="text-xs font-bold">يوم {idx + 1}</div>

                              {config && config.count > 0 && (
                                  <div className="mt-1">
                                      <div className="text-[10px] bg-uh-green/10 text-uh-greenDark rounded-full px-1 truncate font-bold">
                                          {meal ? meal.name : 'وجبة مخصصة'}
                                      </div>
                                      <div className="text-[10px] font-bold text-uh-dark">العدد: {config.count}</div>
                                  </div>
                              )}

                              {config?.status === 'postponed' && (
                                  <div className="text-[8px] text-red-500 font-bold mt-1">مؤجل ⏳</div>
                              )}
                              {isToday && <div className="text-[8px] bg-uh-green text-white rounded mt-1 px-1">اليوم</div>}
                          </div>
                      );
                  })}
              </div>
          </div>
      );
  };

  const filteredSubs = subscriptions.filter(s => filter === 'all' || s.status === filter);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-arabic" dir="rtl">
      {/* Header */}
      <header className="bg-uh-dark text-white p-4 shadow-lg flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-3">
              <div className="bg-uh-green p-2 rounded-lg"><ChefHat size={24} /></div>
              <h1 className="text-xl font-bold">لوحة {isEmployee ? 'موظف' : 'مطبخ'} Uncle Healthy</h1>
          </div>
          <div className="flex items-center gap-4">
              {!isEmployee && (
                  <button onClick={() => setShowAddModal(true)} className="bg-uh-gold text-uh-dark px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-yellow-500 transition shadow-sm">
                      <Plus size={20}/> <span>إضافة اشتراك</span>
                  </button>
              )}
              <button onClick={onLogout} className="text-red-400 hover:text-red-300 transition font-bold flex items-center gap-2"><LogOut size={20}/> <span>خروج</span></button>
          </div>
      </header>

      <main className="flex-1 container mx-auto p-4 md:p-8 space-y-6">

          {/* Dashboard Stats Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات الموزعة</p>
                  <p className="text-2xl font-bold text-uh-green">{subscriptions.reduce((sum, s) => sum + (s.deliveredCount || 0), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الوجبات المتبقية</p>
                  <p className="text-2xl font-bold text-uh-dark">{subscriptions.reduce((sum, s) => sum + (s.totalMeals - (s.deliveredCount || 0)), 0)}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">الطلبات النشطة</p>
                  <p className="text-2xl font-bold text-blue-500">{subscriptions.filter(s => s.status !== 'delivered').length}</p>
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                  <p className="text-xs text-gray-400 font-bold mb-1">أيام التأجيل</p>
                  <p className="text-2xl font-bold text-red-500">{subscriptions.reduce((sum, s) => sum + (s.postponedCount || 0), 0)}</p>
              </div>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
              {['all', 'active', 'out-for-delivery', 'delivered'].map((f) => (
                  <button key={f} onClick={() => setFilter(f as any)} className={`px-4 py-2 rounded-full text-xs font-bold transition whitespace-nowrap ${filter === f ? 'bg-uh-dark text-white' : 'bg-white text-gray-500 border hover:bg-gray-50'}`}>
                      {f === 'all' ? 'الكل' : f === 'active' ? 'بانتظار التجهيز' : f === 'out-for-delivery' ? 'في الطريق' : 'تم التسليم'}
                  </button>
              ))}
          </div>

          <div className="grid gap-6">
              {filteredSubs.map(sub => {
                  const customer = sub.user;
                  const isExpanded = expandedSubId === sub.id;
                  const todayKey = new Date().toISOString().split('T')[0];
                  const todayConfig = sub.dailyConfigs?.[todayKey];
                  const todayMeal = meals.find(m => m.id === todayConfig?.mealId);
                  const remaining = sub.totalMeals - (sub.deliveredCount || 0);

                  return (
                      <div key={sub.id} className={`bg-white rounded-3xl shadow-sm border overflow-hidden transition-all duration-300 ${isExpanded ? 'ring-2 ring-uh-green' : 'border-gray-100'}`}>
                          <div className="grid md:grid-cols-3">

                              <div className="p-6 border-l border-gray-50 relative group">
                                  {!isEmployee && (
                                      <button 
                                        onClick={() => handleDeleteSubscription(sub.id)}
                                        className="absolute top-2 left-2 p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-full transition opacity-0 group-hover:opacity-100"
                                        title="حذف الاشتراك نهائياً"
                                      >
                                          <Trash2 size={18} />
                                      </button>
                                  )}

                                  <div className="flex items-center gap-3 mb-4 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                      <div className="w-12 h-12 bg-uh-cream rounded-full flex items-center justify-center text-uh-dark font-bold"><User size={24}/></div>
                                      <div>
                                          <h3 className="font-bold text-lg text-uh-dark">{customer?.name}</h3>
                                          <div className="flex gap-2 items-center">
                                              <span className="text-[10px] bg-uh-gold/20 text-uh-greenDark px-2 py-0.5 rounded-full font-bold">{sub.planTitle}</span>
                                              <span className="text-[10px] bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full font-bold">بدأ في: {sub.date}</span>
                                          </div>
                                      </div>
                                  </div>
                                  <div className="space-y-2 text-sm">
                                      <a href={`tel:${sub.phone}`} className="flex items-center gap-2 text-blue-600 font-bold"><Phone size={14}/> {sub.phone}</a>
                                      <p className="text-gray-500 flex items-start gap-2"><MapPin size={14} className="mt-1 flex-shrink-0"/> {sub.address}</p>
                                  </div>
                              </div>

                              <div className="p-6 bg-gray-50/50 border-l border-gray-50 cursor-pointer" onClick={() => setExpandedSubId(isExpanded ? null : sub.id)}>
                                  <div className="flex justify-between items-start mb-4">
                                      <h4 className="text-xs font-bold text-gray-400 uppercase">مهمة لليوم</h4>
                                      <div className="flex gap-1">
                                          <span className="text-[10px] bg-white border border-gray-200 px-2 py-0.5 rounded-full font-bold">المتبقي: {remaining}</span>
                                          {isExpanded ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
                                      </div>
                                  </div>

                                  {todayConfig && todayConfig.count > 0 ? (
                                      <div className="bg-white p-3 rounded-2xl shadow-sm border border-uh-green/20">
                                          <div className="flex items-center gap-3">
                                              {todayMeal && <img src={todayMeal.image} className="w-10 h-10 rounded-lg object-cover" alt=""/>}
                                              <div>
                                                  <p className="font-bold text-sm">{todayMeal ? todayMeal.name : 'وجبة مخصصة'}</p>
                                                  <p className="text-uh-green font-bold text-xs">العدد لليوم: {todayConfig.count}</p>
                                              </div>
                                          </div>
                                      </div>
                                  ) : (
                                      <div className="text-center py-4 text-gray-400 text-xs italic">لا توجد وجبات مبرمجة لليوم</div>
                                  )}

                                  <div className="mt-3 p-2 rounded-xl bg-red-50 text-red-700 text-xs font-bold">
                                      ⚠️ {customer?.allergies || 'لا توجد ملاحظات صحية'}
                                  </div>
                              </div>

                              <div className="p-6 flex flex-col justify-between">
                                  <div className="flex justify-between items-center mb-4">
                                      <span className="text-[10px] text-gray-400 font-bold uppercase">الحالة: {sub.status}</span>
                                      <div className="flex items-center gap-1 text-uh-greenDark font-bold text-xs"><Clock size={12}/> {sub.deliverySlot}</div>
                                  </div>

                                  <div className="grid grid-cols-2 gap-2">
                                      {sub.status !== 'delivered' ? (
                                          <>
                                              {sub.status === 'active' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'out-for-delivery', departureTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}) })} className="col-span-2 bg-uh-dark text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-black transition shadow-sm"><Truck size={16}/> خروج الطلب</button>
                                              )}
                                              {sub.status === 'out-for-delivery' && (
                                                  <button onClick={() => handleUpdateStatus(sub.id, { status: 'delivered', arrivalTime: new Date().toLocaleTimeString('ar-EG', {hour: '2-digit', minute:'2-digit'}), deliveredCount: (sub.deliveredCount || 0) + (todayConfig?.count || 1) })} className="col-span-2 bg-uh-green text-white py-2 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-uh-greenDark transition shadow-md"><CheckCircle size={16}/> تم التسليم</button>
                                              )}
                                              <button onClick={() => handlePostpone(sub)} className="col-span-2 border border-red-200 text-red-500 py-2 rounded-xl text-xs font-bold hover:bg-red-50 transition">تأجيل لليوم (تمديد الاشتراك)</button>
                                          </>
                                      ) : (
                                          <div className="col-span-2 bg-green-50 text-green-700 py-2 rounded-xl text-center font-bold text-xs border border-green-100 animate-pulse">اكتمل التوصيل اليوم ✅</div>
                                      )}
                                  </div>
                              </div>
                          </div>

                          {isExpanded && <div className="p-6 bg-gray-50/20 border-t border-gray-100">{renderMonthlySchedule(sub)}</div>}
                      </div>
                  );
              })}
          </div>
      </main>

      {/* Day Editing Modal (Only for Chefs, not Employees) */}
      {showDayModal && activeDayEdit && !isEmployee && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in">
              <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl relative">
                  <div className="flex justify-between items-center mb-6">
                      <div className="flex items-center gap-2 text-uh-dark">
                          <Edit3 className="text-uh-green" />
                          <h3 className="font-bold text-xl">برمجة يوم: {activeDayEdit.date}</h3>
                      </div>
                      <button onClick={() => setShowDayModal(false)} className="text-gray-400 hover:text-uh-dark"><X/></button>
                  </div>

                  <div className="space-y-6">
                      <div>
                          <label className="block text-sm font-bold mb-2">اختر صنف الوجبة من المتجر</label>
                          <select 
                            className="w-full border p-4 rounded-xl bg-gray-50 outline-none focus:ring-2 focus:ring-uh-green transition"
                            value={dayEditForm.mealId}
                            onChange={e => setDayEditForm({...dayEditForm, mealId: e.target.value})}
                          >
                              <option value="">اختر وجبة من القائمة...</option>
                              {meals.map(m => <option key={m.id} value={m.id}>{m.name} - {m.macros.calories} سعرة</option>)}
                          </select>
                      </div>

                      <div>
                          <label className="block text-sm font-bold mb-2 flex items-center gap-2"><Hash size={16} className="text-uh-gold"/> عدد الوجبات لهذا اليوم</label>
                          <div className="flex items-center gap-6 bg-gray-100 p-4 rounded-2xl justify-center">
                              <button onClick={() => setDayEditForm({...dayEditForm, count: Math.max(0, dayEditForm.count - 1)})} className="bg-white w-10 h-10 rounded-full shadow-md flex items-center justify-center hover:bg-gray-50 transition"><Minus size={18}/></button>
                              <span className="text-2xl font-bold w-12 text-center text-uh-dark">{dayEditForm.count}</span>
                              <button onClick={() => setDayEditForm({...dayEditForm, count: dayEditForm.count + 1})} className="bg-white w-10 h-10 rounded-full shadow-md flex items-center justify-center hover:bg-gray-50 transition"><Plus size={18}/></button>
                          </div>
                      </div>

                      <button onClick={saveDayConfig} className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg hover:bg-uh-greenDark transition transform hover:-translate-y-1">حفظ إعدادات اليوم</button>
                  </div>
              </div>
          </div>
      )}

      {/* Add Subscription Modal (Only for Chefs, not Employees) */}
      {showAddModal && !isEmployee && (
          <div className="fixed inset-0 z-[110] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in overflow-y-auto">
              <div className="bg-white rounded-3xl w-full max-w-xl p-8 shadow-2xl my-8 relative">
                  <div className="flex justify-between items-center mb-6 border-b pb-4">
                      <h3 className="text-xl font-bold flex items-center gap-2"><Plus className="text-uh-green" /> تفعيل اشتراك زبون جديد</h3>
                      <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-red-500 transition"><X /></button>
                  </div>

                  <form onSubmit={handleAddSub} className="space-y-4">
                      <div className="grid md:grid-cols-2 gap-4">
                          <input required placeholder="اسم الزبون الكامل" className="border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" value={newSub.customerName} onChange={e => setNewSub({...newSub, customerName: e.target.value})} />
                          <input required type="tel" placeholder="رقم هاتف الزبون" className="border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" value={newSub.phone} onChange={e => setNewSub({...newSub, phone: e.target.value})} />
                      </div>
                      <textarea required placeholder="العنوان بالتفصيل" className="w-full border p-4 rounded-xl bg-gray-50 outline-none focus:bg-white transition" rows={2} value={newSub.address} onChange={e => setNewSub({...newSub, address: e.target.value})} />
                      <div className="grid md:grid-cols-3 gap-4">
                          <div className="md:col-span-2">
                              <select required className="w-full border p-4 rounded-xl bg-gray-50 outline-none" value={newSub.planId} onChange={e => setNewSub({...newSub, planId: e.target.value})}>
                                  <option value="">اختر باقة...</option>
                                  {plans.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <input type="number" className="w-full border p-4 rounded-xl bg-gray-50 outline-none" value={newSub.totalMeals} onChange={e => setNewSub({...newSub, totalMeals: Number(e.target.value)})} />
                      </div>
                      <button type="submit" className="w-full bg-uh-green text-white font-bold py-4 rounded-2xl shadow-lg mt-4 hover:bg-uh-greenDark transition-all active:scale-95">حفظ وتفعيل عضوية الزبون</button>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

